INSERT INTO `activity` VALUES (14,1,'近期想去四川旅游，玩成都、九寨、稻城求搭子！','四川景点多，而且分布很散，很难规划完美的旅游路线，还好我去过四川旅游的朋友给我介绍了一个四川当地的导游晶晶，她帮我们免费规划整个行程，帮我们安排好了全程的吃、住、行。吃的都是四川特色美食、住也都在景区4星级酒店，不用景区和市区来回跑，整个行程都很轻松。最重要的是，她帮我们安排了VIP购票通道，全程的景点都不用排队，让我们有更多的时间欣赏各个景点的美景。','https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/283012d5-6473-4b16-8775-25aa038d5931.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/41232ca0-68df-4328-80c2-8a6bf6923ca4.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/e44aefc0-b21a-4471-94a9-4ae66166bdcd.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/a66fb110-d8e9-4073-bf8e-1e9c8553c7b3.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/3c0abc6e-eb04-4357-ae4c-0a3594b7bb32.jpg','2023年12月10日12时00分','九寨沟景区',10,'2026-04-19 22:39:09','2026-02-01 23:36:48',0),(15,3,'西藏旅行，求两个搭子(AA)','夏日的西藏是属于喧嚣的，冬日才能遇见真正的西藏，没有人挤人，也不需要抢票，气温在10度左右，晴朗少雨，旅行体验感更佳。','https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/0d50abc8-b84b-4e68-8d54-3c10aa9c83cf.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/8880853e-5dec-4664-8983-0d0d5bdd1c1d.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/8c4e6c33-9802-4372-84ec-da07b30b7d3c.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/3ddec523-48da-4bd5-b0de-45a220c71640.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/a0c14a2c-1e4a-4b48-a162-0c203253fe52.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/3b5c6ab6-4352-4be6-ae89-9a938c8fa6a7.jpg','2023年12月25日10时30分','布达拉宫',3,'2026-03-15 02:06:33','2026-01-30 11:42:25',0),(16,18,'江南古镇','总要去一趟江南六大古镇之一的西塘吧！或轻舟慢度，走一走江南烟水路，或凭栏听曲，瞧一瞧人间风光处，这里的青砖灰，小桥流水人家，寻常巷陌无不充满了诗意与美好！','https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/8071c572-e2cb-465d-b373-7c4b2c7c07d3.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/2331f57b-4313-432c-8466-cc604ca3a99c.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/176d86c6-fbbc-472e-89ac-a3bb2935e523.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/21d0fc05-b542-4b2e-abc3-36311a7e26aa.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/a3583943-78d0-4cdd-a3c4-1eac138cc447.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/c158b564-12eb-4479-bb32-40b30d8d89ba.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/c7799e59-6359-4b76-8aa4-c4a693f17ddb.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/6eefb720-0f4f-49bc-afaf-3bbfb6270a99.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/6d28c61a-cce3-483b-baa5-e342df8ed861.jpg,https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/0fbfc60f-45a4-42cb-b57b-9e5241c67cd2.jpg','2024年07月11日09时30分','西塘古镇景区',6,'2026-02-18 04:12:25','2026-02-02 09:54:49',0),(18,4,'去新疆！！！','主打随性，说走就走','https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/a3a94c77-4b44-4fb7-ade9-68cdf1e84c23.jpg','2025年07月01日10时00分','赛里木湖',4,'2026-01-18 12:56:54','2026-04-21 11:00:03',0);

