  `workspace_slug` varchar(128) DEFAULT NULL,
  `vector_location` varchar(512) DEFAULT NULL,
  `indexed` tinyint DEFAULT '0',
  `sync_status` varchar(32) DEFAULT 'pending',
  `retry_count` int DEFAULT '0',
  `next_retry_time` datetime DEFAULT NULL,
  `last_success_time` datetime DEFAULT NULL,
  `last_error` varchar(512) DEFAULT NULL,
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_doc_provider_workspace` (`doc_id`,`provider`,`workspace_slug`),
  KEY `idx_biz` (`biz_type`,`biz_id`),
  KEY `idx_hash` (`content_hash`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
