DROP TABLE IF EXISTS `ai_itinerary`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ai_itinerary` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `title` varchar(100) DEFAULT NULL COMMENT '行程标题',
  `destination` varchar(100) DEFAULT NULL COMMENT '目的地',
  `days` int DEFAULT '3' COMMENT '旅行天数',
  `theme` varchar(100) DEFAULT NULL COMMENT '旅行主题',
  `budget` varchar(50) DEFAULT NULL COMMENT '预算',
  `people` int DEFAULT '1' COMMENT '出行人数',
  `content` longtext COMMENT 'AI生成的完整行程内容',
  `cover_img` varchar(500) DEFAULT NULL COMMENT '封面图URL',
  `session_id` bigint DEFAULT NULL COMMENT '来源AI会话ID',
  `collab_room_id` bigint DEFAULT NULL COMMENT '协作房间ID，NULL表示个人行程',
  `is_collab` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否为协作行程 0否 1是',
  `contributors` varchar(500) DEFAULT NULL COMMENT '参与协作的用户ID列表，JSON数组',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `deleted` tinyint NOT NULL DEFAULT '0',
  `route_id` bigint DEFAULT NULL COMMENT '关联路线ID',
  `travel_type` varchar(50) DEFAULT NULL COMMENT '出行类型',
  `plan_days_json` longtext COMMENT '按天结构化行程JSON',
  `detail_source` varchar(20) DEFAULT 'ai' COMMENT '详情来源: ai/local/mixed',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_create_time` (`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='AI智能行程表';
