INSERT INTO `ai_itinerary` VALUES (1,1,'三亚5天亲子海岛游','三亚',5,'亲子','8000元',3,'{\"days\":[{\"day\":1,\"title\":\"抵达三亚·安营扎寨\",\"items\":[\"入住亚龙湾酒店\",\"傍晚漫步亚龙湾海滩\",\"享用海鲜大排档晚餐\"]},{\"day\":2,\"title\":\"蜈支洲岛·水上乐园\",\"items\":[\"乘船前往蜈支洲岛\",\"浮潜体验珊瑚礁\",\"岛上午餐\",\"下午返回逛免税店\"]},{\"day\":3,\"title\":\"天涯海角·南山文化\",\"items\":[\"上午参观天涯海角\",\"下午游览南山寺\",\"祈福还愿\"]},{\"day\":4,\"title\":\"热带雨林·亲子探险\",\"items\":[\"呀诺达热带雨林\",\"植物科普教育\",\"篝火晚会\"]},{\"day\":5,\"title\":\"购物返程\",\"items\":[\"海棠湾免税城购物\",\"整理行李\",\"乘机返程\"]}]}',NULL,NULL,NULL,0,NULL,'2026-03-26 03:59:09',0,NULL,NULL,NULL,'ai'),(2,2,'北京4天历史文化深度游','北京',4,'文化','6000元',2,'{\"days\":[{\"day\":1,\"title\":\"故宫·景山·王府井\",\"items\":[\"上午故宫博物院\",\"景山公园俯瞰故宫\",\"王府井小吃街晚餐\"]},{\"day\":2,\"title\":\"长城·明十三陵\",\"items\":[\"慕田峪长城徒步\",\"十三陵定陵参观\",\"特色烤鸭晚餐\"]},{\"day\":3,\"title\":\"颐和园·圆明园·798\",\"items\":[\"颐和园游船\",\"圆明园遗址参观\",\"798艺术区\"]},{\"day\":4,\"title\":\"胡同文化·南锣鼓巷\",\"items\":[\"骑行胡同\",\"南锣鼓巷文艺小店\",\"乘机返程\"]}]}',NULL,NULL,NULL,0,NULL,'2026-01-25 05:27:37',0,NULL,NULL,NULL,'ai'),(3,1,'成都3天美食休闲游','成都',3,'美食','4000元',2,'{\"days\":[{\"day\":1,\"title\":\"宽窄巷子·锦里\",\"items\":[\"宽窄巷子漫步\",\"锦里古街\",\"品尝正宗火锅\"]},{\"day\":2,\"title\":\"大熊猫基地·武侯祠\",\"items\":[\"早起参观大熊猫基地\",\"下午武侯祠·锦江\",\"晚上酒吧街夜生活\"]},{\"day\":3,\"title\":\"青城山·都江堰\",\"items\":[\"青城山登山\",\"都江堰水利工程参观\",\"返程\"]}]}',NULL,NULL,NULL,0,NULL,'2026-04-19 15:20:39',0,NULL,NULL,NULL,'ai');

