INSERT INTO `attractions` VALUES (1,'贵州','贵州安顺黄果树风景名胜区1111','安顺市镇宁布依族苗族自治县黄果树镇','黄果树大瀑布是世界著名大瀑布之一，被誉为中国最美的地方，出名始于明代旅行家徐霞客，经过历代名人的游历、传播，成为知名景点。黄果树风景名胜区以黄果树瀑布景区为中心，分布有天星桥景区、陡坡塘景区、滴水滩瀑布景区、郎宫景区、霸陵河峡谷三国古驿道景区、郎宫景区、以石头寨为首的黄果树布依族十大村寨等几大景区，为黄果树风景名胜区，国家首批5A级旅游区、国家重点风景名胜区，贵州省安顺市镇宁布依族苗族自治县，距贵阳市128公里。','180元','http://store.is.autonavi.com/showpic/5034b3c2f0e8dae92dd2467e4fbc21fe?type=pic,http://store.is.autonavi.com/showpic/edac48be6400f97f22affb4662a5e585?type=pic,http://store.is.autonavi.com/showpic/ffa9f0cf33b206f73f40541674f24dc0?type=pic,http://store.is.autonavi.com/showpic/7969e2d43937b3721f7edf69c2b3371d?type=pic,http://store.is.autonavi.com/showpic/079043336333e8d9b9d6ff7aa927b1f4?type=pic','105.668716,25.988506',5,0,'2026-04-21 12:20:22','2026-04-17 15:39:56'),(2,'贵州','贵州铜仁梵净山风景区','铜仁市江口县杭瑞高速附近','梵净山被称为“贵州第一名山，武陵第一峰”，无论是自然风景还是人文景观，都极为丰富。梵净山“集黄山之奇，峨眉之秀，华山之险，泰山之雄”，这里留下了10至14亿年前形成的奇特地貌景观，亿万斯年的风雨侵蚀，雕琢了老金顶附近的高山石林峰群，鬼斧神工，惟妙惟肖，妙趣天成，众多奇石是景区内的一大特点，更有佛光、禅雾、幻影和瀑布云四大天象。梵净山是全国著名的弥勒菩萨道场和中国第五大佛教名山之一，有释迦殿、弥勒殿、承恩寺等庙宇，在佛教史上具有重要的地位。','110元','http://store.is.autonavi.com/showpic/9461b5bb247f6eaa265d9fe319eac3ab?type=pic,http://store.is.autonavi.com/showpic/694398eadb58fb96cb9af8e97c6b5c0b?type=pic,http://store.is.autonavi.com/showpic/b05a3def5a13095e81de715960a70d68?type=pic,http://store.is.autonavi.com/showpic/e3725a478258a573698a5073679c73af?type=pic','108.720359,27.882738',4,0,'2026-03-23 17:18:34','2026-03-30 15:33:02'),(3,'贵州','贵州毕节百里杜鹃景区','毕节市大方县普底乡大荒村','百里杜鹃旅游景区，素有“地球彩带·世界花园”之美誉，是世界上最大的天然花园，是国家5A级景区、国家级森林公园，贵州省十大魅力旅游景区之一。百里杜鹃不仅是杜鹃花的海洋、杜鹃花的世界，而且还是参天古树云集、山水林洞辉映、珍禽栖息、民族风情浓郁的原始森林旅游景区。公园内有对嘴岩、杜鹃湖、百里杜鹃大草原等40多个景点，是春季赏花、夏季避暑的理想之地。','①3月10日至5月15日150元(不含观光车费)。 ②5月16日至次年3月9日75元(含观光车费)。 ③观光车票金坡、普底分段票价格分别为35元。','http://store.is.autonavi.com/showpic/23cc5d623da12c7aae037c57be359b86?type=pic,http://store.is.autonavi.com/showpic/bbf3646185b94e58590d131e91dc7ffd?type=pic,http://store.is.autonavi.com/showpic/21c7951432cdaea1449764d34e049680?type=pic,http://store.is.autonavi.com/showpic/6d2cd8070bd6b755cecb43e1162eb0ff?type=pic','105.915619,27.215567',5,0,'2026-03-20 01:49:29','2026-01-05 10:28:20'),(4,'贵州','贵州安顺龙宫风景名胜区','安顺市西秀区兴龙路','安顺龙宫风景名胜区被誉为“天下喀斯特，尽在龙宫”，景区以水溶洞群为主体，更集旱溶洞、瀑布、峡谷、峰丛、绝壁、湖泊、溪河、民族风情、宗教文化于一身，构成一幅怡然自得的人间仙境画图，为国家5A级景区。安顺龙宫是一个大型暗湖溶洞，是喀斯特地貌形态展示最为集中全面的景区，全洞长3500米，穿越20余座山峰，连接90余个洞穴，包括水洞、旱洞、天池、瀑布、石林、峡道及附近布依族石头村寨等。','150元','http://store.is.autonavi.com/showpic/51f674fdfb177da5cf88dd5a24561a0c?type=pic,http://store.is.autonavi.com/showpic/8c79d54cfee9171d322ffad5453da339?type=pic,http://store.is.autonavi.com/showpic/e0855a6c118ca8709b2aa85b502af752?type=pic,http://store.is.autonavi.com/showpic/238518a01433a65b307a5afc4f504214?type=pic','105.885762,26.106874',4,0,'2026-01-28 22:53:15','2026-01-07 11:01:17'),(5,'贵州','贵州荔波樟江景区','黔南布依族苗族自治州荔波县瑶山瑶族乡梦柳风情小镇对面游客集散中心','荔波樟江风景名胜区，由大七孔、小七孔、水春河和樟江风光带四个景区组成，集洞、林、湖、瀑、石、水多种景观于一体，为国家5A级景区，世界自然遗产。大七孔以进入景区的一座大七孔古桥而得名。景区内分布着原始森林、峡谷、伏流、地下湖等，充满了神秘、奇特的色彩。','①小七孔门票参考价：淡季90元，旺季110元，观光车车票40元，鸳鸯湖自助手划船船票30元/小时; ②大七孔门票参考价：淡季45元，旺季55元，游船船票20元(单程); ③水春河和樟江风光：免费。','http://store.is.autonavi.com/showpic/29a57471198819c4e161606e326a3165?type=pic,http://store.is.autonavi.com/showpic/45d177f248e84d372f1c3af2f40995a4?type=pic,http://store.is.autonavi.com/showpic/5fcec1ff597408f70bccd2e750424e46?type=pic,http://store.is.autonavi.com/showpic/19e732b188ea5a61cd303bc941a665eb?type=pic','107.760566,25.280047',4,0,'2026-03-10 10:26:38','2026-03-24 19:09:20'),(6,'贵州','贵州赤水丹霞景区','遵义市赤水市元厚镇五柱峰','赤水丹霞旅游区由赤水大瀑布、佛光岩、燕子岩三大景段组成，素有“千瀑之市、丹霞之冠、竹子之乡、桫椤王国”的美誉。赤水丹霞是世界自然遗产赤水丹霞核心景区，是赤水国家重点风景名胜区的王牌景区，也是国家地质公园、国家森林公园、国家级自然保护区，走进赤水丹霞旅游区，艳丽鲜红的丹霞赤壁，拔地而起的孤峰窄脊，仪态万千的奇山异石，巨大的岩廊洞穴和优美的丹霞峡谷与绿色森林、飞瀑流泉相映成趣，具有极高的观赏价值，令人倾倒。','①赤水大瀑布景区90元，②燕子岩森林公园60元;③丙安古镇(红军四渡赤水)20元;④四洞沟景区85元，⑤桫椤保护区50元;⑥竹海国家森林公园60元;⑦佛光岩景区(丹霞世界遗产申报地)90元;','http://store.is.autonavi.com/showpic/a85858cd70a91fc13a8c9e7f05f3a7ad?type=pic,http://store.is.autonavi.com/showpic/6dd81f027ba8be5c331e50bd9ac7a396?type=pic,http://store.is.autonavi.com/showpic/b564d8cbb46a53e6ff88205ae1ed6e87?type=pic,http://store.is.autonavi.com/showpic/72aabfe495540852c0bfbe68fb3f674c?type=pic,http://store.is.autonavi.com/showpic/4809cc2e899b777a840d0c5617b7fba6?type=pic','105.948589,28.399094',4,0,'2026-03-30 16:26:49','2026-03-17 00:46:03'),(7,'贵州','贵州镇远古城景区','黔东南族侗族自治镇远县兴隆街21号','镇远古镇旅游资源非常丰富，被誉为“传统文化的迷宫”、“自然与文化的完美结合的胜地”。集文化名城、名山丽水、自然文化、民族分情为一体。因此也被誉为“完美的山水古城、难得的度假胜地”。镇远古城占地3.1平方公里，古城有八大会馆、四洞、八祠、九庙、十二码头与府卫古城洹，吴王洞、四宫殿、古全井、古戏楼等名胜古迹近200多处。镇远古镇的气候温和，雨量充沛，属亚热带季风湿润气候，年平均气温在16.4度，冬无严寒、夏无酷暑、春秋温煦。','80元','https://aos-comment.amap.com/B03570161S/headerImg/1038a8f24d22b71d8f237cd822a1608b_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/4c4b8fe0501997a9be07ed1139fccbdb?type=pic,http://store.is.autonavi.com/showpic/039e4c5405faad9930e8ada71c486483?type=pic,http://store.is.autonavi.com/showpic/87978b90ed858c73e0a14730d028cfd7?type=pic,http://store.is.autonavi.com/showpic/b6f871677c4957c68393854c98c78981?type=pic','108.421039,27.047373',3,0,'2026-04-20 02:29:51','2026-03-22 10:11:04'),(8,'贵州','贵州肇兴侗寨景区','黔东南苗族侗族自治州黎平县肇兴村202省道','肇兴侗寨是黎平侗乡风景名胜区的核心景点，是黔东南侗族地区最大的侗族村寨，也是侗族的民俗文化中心，以鼓楼和歌舞著称，素有\"侗乡第一寨\"之美誉，被《中国国家地理》评选为“中国最美的六大乡村古镇”之一。肇兴侗寨四面环山，寨子建于山中盆地，两条小溪汇成一条小河穿寨而过。寨中房屋为干栏式吊脚楼，鳞次栉比，错落有致。肇兴侗寨全为陆姓侗族，分为5个自然村(团)，分别称为“仁、义、礼、智、信”。共建有鼓楼五座，花桥五座、戏台五座。其中以智寨鼓楼最为美观。','免费','http://store.is.autonavi.com/showpic/8915a9f9db424750433e02172c097399?type=pic,http://store.is.autonavi.com/showpic/1a8246a721068f706bd3faa76b3dc11a?type=pic,http://store.is.autonavi.com/showpic/e852fafdeace698e04dd8f8b76f77f29?type=pic,https://aos-comment.amap.com/B0FFF73RYK/headerImg/7004509f0a15abcba073085ae287e2aa_2048_2048_80.jpg?type=pic','109.149009,25.906612',2,0,'2026-03-16 19:25:49','2026-01-13 18:35:56'),(9,'贵州','贵州紫云格凸河穿洞景区','安顺市紫云苗族布依族自治县紫云洞路与文化路交叉口西北280米','紫云格凸河穿洞风景名胜区有堪称一绝的世界最高古河道遗迹穿上洞、盲谷，举世无双的大穿洞绝景燕王宫，巨大幽深、气势恢宏的世界第二大洞穴厅室苗厅，国内最深的岩溶竖井通天洞……燕王宫数万鹰燕早晚竞翔，天星洞百具苗族祖先悬棺洞葬，洞外峡谷景观壮丽，田园风光旖旎，苗寨风情纯朴。紫云格凸河穿洞景区面积70平方公里，主要有黄家湾、大穿洞、大河、小穿洞四个大景区，极富神秘感，具有探险、旅游、科考价值，是中国国家级风景区，中国自然与文化双遗产地，中国南方喀斯特申报世界自然遗产入选地。','190元','https://youimg1.c-ctrip.com/target/100916000000zvo0gE2B9.jpg,https://ts1.cn.mm.bing.net/th/id/R-C.9fa70f1dd30d09734207e43d4ad285a7?rik=9YfBuOu10TEPvA&riu=http%3a%2f%2fwww.peopleweekly.cn%2fuploadfile%2f2019%2f0902%2f20190902044543266.jpg&ehk=SXzBV5%2bSXF4abJK0lEi%2bWN%2bmV8hYkzOrVD5n8Rgcb3o%3d&risl=&pid=ImgRaw&r=0,https://youimg1.c-ctrip.com/target/100k15000000xdhh5E594.jpg,https://youimg1.c-ctrip.com/target/100o1g000001h88ox8C0D.jpg','106.265122,25.677971',4,0,'2026-03-21 10:42:12','2026-04-29 21:43:13'),(10,'贵州','贵州遵义海龙囤军事古堡景区','遵义市汇川区高坪街道办海龙屯景区','海龙屯又被称为龙岩屯，是宋、元、明时期西南播州杨氏土司文化的重要遗存，列世界遗产名录，为全国重点文物保护单位。屯上最高海拔1354米，屯下海拔974米，相对高差300-400米左右。屯顶平阔，面积约1.59平方公里。屯上前后建有九关，屯前有六关，屯后建有三关，九关之间，各关有护墙相连，随山势绵延十余里，别有一翻气象。屯顶建有衙署和练兵场等建筑，规模宏大且壮观。','80元','http://store.is.autonavi.com/showpic/2f6d48c0eadbb169bd635bac46b7f9e6?type=pic,http://store.is.autonavi.com/showpic/f6e894f31f267a1a1fd675d8cda0c251?type=pic,http://store.is.autonavi.com/showpic/fb291d38de76d17280596efa2dc24f84?type=pic,http://store.is.autonavi.com/showpic/adb12ada5745cd7395bfe733109ee11d?type=pic','106.870651,27.804696',5,0,'2026-04-27 04:29:30','2026-04-15 05:17:51'),(11,'北京','北京环球度假区','北京市通州区京哈高速与东六环路交汇处西北角','北京环球度假区（北京环球主题公园、北京环球影城）是亚洲的第三座、全球第五座环球影城主题乐园。乐园总面积超4平方千米，由哈利·波特的魔法世界、变形金刚基地、功夫熊猫盖世之地、好莱坞、未来水世界、小黄人乐园、侏罗纪世界努布拉岛七大主题景区构成，涵盖37处骑乘娱乐设施及地标景点，是节假日陪家人或是爱人一起游玩的好去处，也是一个以全新精选景区为主打，网罗全世界环球主题公园人气最高的娱乐设施和景点。','458-748元','https://aos-comment.amap.com/B0FFHMS3CA/headerImg/e7174a9224e1fd979e955482b2fe61cc_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/2732b61ede48a87569a49181b4541f4e?type=pic,http://store.is.autonavi.com/showpic/b649b72394f8789128c408b1cda4f455?type=pic,http://store.is.autonavi.com/showpic/378731641f7f93d54d87948dd1bba97a?type=pic','116.681212,39.852698',5,0,'2026-02-22 13:00:48','2026-03-12 01:10:26'),(12,'北京','北京欢乐谷','北京市朝阳区东四环小武基北路','北京欢乐谷是新北京十六景、北京文化创意产业基地，由华侨城集团创办，是集国际化、现代化为一体的主题公园，位于朝阳区东四环四方桥东南角。北京欢乐谷由\"峡湾森林、爱琴港、失落玛雅、香格里拉、甜品王国、远古文','299元','http://store.is.autonavi.com/showpic/5b85bb7e762c7c7b84e1563572f3ea8c?type=pic,http://store.is.autonavi.com/showpic/f6874ef301404152aec6a5d6189df312?type=pic,http://store.is.autonavi.com/showpic/42863f890650104b555ad142c77b64e9?type=pic,http://store.is.autonavi.com/showpic/113160d3336f89dba8efbc27169d1937?type=pic','116.494743,39.867355',4,0,'2026-03-14 14:49:45','2026-02-02 22:37:30'),(13,'北京','八达岭长城','北京市延庆区八达岭镇军都山关沟古道北口','八达岭长城以其宏伟的景观、完善的设施和深厚的文化历史内涵而著称于世，是举世闻名的旅游胜地。最是春花铺锦，夏绿叠云，展向天边去，神往青冥。漫道红衰翠减，爱丹林浓染，秋气澄清。更冬来莽莽雪岭，玉龙腾春，风光尽收方寸。望关山无限古今情，凭交付几行征雁，万种心声”。这里四季皆适宜游览，是北京最好玩的旅游景区。','旺季40元，淡季35元','http://store.is.autonavi.com/showpic/e4acea37db056fa0d2b3527b815ca0ed?type=pic,http://store.is.autonavi.com/showpic/1e40be87e9378cb4171902a6438c5018?type=pic,http://store.is.autonavi.com/showpic/ec4c15c7aa0c12e81af272d172b1126e?type=pic,http://store.is.autonavi.com/showpic/9f40ef83c7e87bd9f25d521705bf3601?type=pic,http://store.is.autonavi.com/showpic/5430e4b48c112d1e37038e654068b525?type=pic','116.016802,40.356188',5,0,'2026-03-08 20:38:17','2026-04-26 11:18:56'),(14,'北京','颐和园','北京市海淀区新建宫门路19号','颐和园是以昆明湖、万寿山为基址，以杭州西湖为蓝本，汲取江南园林的设计手法而建成的一座大型山水园林，也是保存最完整的一座皇家行宫御苑，被誉为“皇家园林博物馆”。颐和园园藏文物计有四万余件，品类涉及铜器、玉器、瓷器、木器、漆器、书画、古籍、珐琅、钟表、竹器、乐器、根雕、杂项等，几乎涵盖了中国传世文物的所有门类。','旺季：30元，淡季：20元','http://store.is.autonavi.com/showpic/705842d6120d4f56ddf4a0c5f21c12a6?type=pic,http://store.is.autonavi.com/showpic/b666509a70c112a1e032c0cc267624b2?type=pic,http://store.is.autonavi.com/showpic/fb5a514cc4c2eb08e5814fad6c1dae3a?type=pic,http://store.is.autonavi.com/showpic/fe4284deb69a272e7767ca23d6b7ffb4?type=pic','116.275115,39.999686',4,0,'2026-01-17 18:39:51','2026-04-08 11:22:26'),(15,'北京','故宫博物院','北京市东城区景山前街4号','北京故宫，旧称紫禁城，是中国最大的古代文化艺术博物馆，也是中国明清两代的皇家宫殿，与法国凡尔赛宫、英国白金汉宫、美国白宫、俄罗斯克里姆林宫并称世界五大宫殿。故宫宫城周围环绕着高12米，长3400米的宫墙，形式为一长方形城池，墙外有52米宽的护城河环绕，形成了一个森严壁垒的城堡。下面MaiGoo旅游小编从故宫景点、门票、旅游线路以及周边景区等方面为你介绍北京故宫旅游攻略。','60元','http://store.is.autonavi.com/showpic/51bfe4f5c40d1975f09e563e3c0ecdd6?type=pic,http://aos-cdn-image.amap.com/sns/ugccomment/bd032042-7307-4d70-a301-9be826eb9639.jpg?type=pic,http://store.is.autonavi.com/showpic/87236045073ba32485c7391c3a8bde83?type=pic,http://store.is.autonavi.com/showpic/95dd4277974377aaa74996ddeb2dab46?type=pic','116.397029,39.917839',3,0,'2026-03-19 00:52:36','2026-04-03 18:15:46'),(16,'重庆','武隆天生三桥','重庆武隆县城东南23公里的白果乡与核桃乡交界处','天生三桥，国家5A级景区武隆喀斯特旅游区之一，景区内天生石桥气势磅礴，林森木秀、飞泉流瀑，包容了山、水、雾、泉、峡、峰、溪、瀑，是一处高品位的生态旅游区。','旺季(03月至10月) 95元+45元转车费，淡季(11月至2月)50元+45元转车费','http://store.is.autonavi.com/showpic/149ebcc3b083e4f296b7b9450a1c95f3?type=pic,https://aos-comment.amap.com/B00170I6E1/headerImg/879759b2836707d9ab287d7aaa666a45_2048_2048_80.jpg?type=pic,https://aos-comment.amap.com/B00170I6E1/headerImg/9acff241a840763fe86a7a752c94ecfc_2048_2048_80.jpg?type=pic','107.804818,29.433682',5,0,'2026-04-23 16:41:03','2026-02-15 04:37:55'),(17,'重庆','磁器口古镇','庆市沙坪坝区磁南街1号','中国历史文化名街，重庆市重点保护传统街，重庆“新巴渝十二景”，巴渝民俗文化旅游圈。来磁器口古镇，踩踩青石板路，品尝当地的特色小吃，找个茶馆坐坐，感受下重庆的风土人情。从正门进去，石板路很窄，两边是摊贩店铺。有很多小吃和特产，陈麻花和鸡杂店尤其扎堆，适合一路吃吃逛逛。不喜热闹的旅行者转走其中的小巷，可以品味到最真实的生活。','免费','http://store.is.autonavi.com/showpic/a932c08dd2cfbfde029e78dd78ee1008?type=pic,http://store.is.autonavi.com/showpic/b60881a98132d978bf2a56deaa0fe3e7?type=pic,http://store.is.autonavi.com/showpic/02a5cb03cedf48d5cd92730f47dd614e?type=pic,https://aos-comment.amap.com/B00170IFE4/headerImg/content_media_external_images_media_13743_ss_2_1689333124196_cd739a65.jpg?type=pic','106.449691,29.581173',4,0,'2026-01-08 21:06:30','2026-01-24 19:38:45'),(18,'重庆','解放碑','重庆市渝中区民族路177号','抗战胜利纪功碑暨人民解放碑是重庆的地标之一，是抗战胜利的精神象征，是中国唯一一座纪念中华民族抗日战争胜利的纪念碑，也是重庆解放历史的见证。以解放碑为中心的十字路口，包括周边的民权路、邹容路和八一路等，这里是重庆最繁华的商业圈。这里的八一路好吃街，几乎能吃到所有的重庆美食，周围有国泰广场、重白大楼、大都会东方广场、协信星光广场、八一广场、重庆时代广场等是逛街的好去处。参观解放碑最好的时间是晚上，重庆市民夜生活开始的时候，整个解放碑区域就是人流最扎堆的地方。','免费','http://store.is.autonavi.com/showpic/702ac17d307211291c4e7f2b478582da?type=pic,http://store.is.autonavi.com/showpic/820c0a3c1e77869ddc46414df85d665a?type=pic,http://store.is.autonavi.com/showpic/163bb54025f0f750318a01924504731c?type=pic,http://store.is.autonavi.com/showpic/66acecbcd94bb64c84f558a846bac97f?type=pic','106.575329,29.557253',4,0,'2026-04-06 10:54:17','2026-02-15 19:35:10'),(19,'重庆','酉阳桃花源景区','重庆市酉阳县钟多镇','酉阳桃花源景区与陶渊明笔下《桃花源记》描述的世外桃源极其吻合，因自古武陵山地区“蛮不出洞、汉不入境”的皇命戒律，景区在武陵大山中沉睡了1600余年。酉阳桃花源系国家5A级旅游景区 、国家级森林公园，位于重庆酉阳自治县城区，由世外桃源、伏羲洞 、桃花源国家森林公园、桃花源广场、酉州古城、二酉山等六大部分组成。','128元','http://store.is.autonavi.com/showpic/79a29010b74fbd6e9ef861401167846d?type=pic,http://store.is.autonavi.com/showpic/ad7ddb2714c66977af8a0d14aa8df11b?type=pic,http://store.is.autonavi.com/showpic/e60d21abbaf871de3380e36719059cd6?type=pic,http://store.is.autonavi.com/showpic/99d6c540de5ca78bc0b7c076a3378057?type=pic','108.752353,28.858176',5,0,'2026-03-04 17:13:01','2026-02-26 03:19:37'),(20,'重庆','巫山小三峡景区','重庆市巫峡镇大宁河河口','巫山小三峡，国家5A级景区、国家级重点风景名胜区，被名人誉为“中华奇观”，“天下绝景”。巫山小三峡是长江三峡段的第一大支流大宁河下游在巫山境内的龙门峡、巴雾峡、滴翠峡三段峡谷的总称。她一江碧水、奇峰壁立、竹木葱葱、猿声阵阵、饶有野趣，是一处巧夺天工的自然画廊。同时被誉为全国最佳漂流区，有惊无险的回归大自然参与式漂流——被称为“中国第一漂”。','150元','http://store.is.autonavi.com/showpic/3b16e61bcff85aa80af283ae104becbf?type=pic,http://store.is.autonavi.com/showpic/a5d5f0e4318408cff0ed49bc432c1dce?type=pic,http://store.is.autonavi.com/showpic/626106f1a7f15cf7212cb252069e7b42?type=pic,http://store.is.autonavi.com/showpic/281afa3efe1092c163a87eb8456ec736?type=pic','109.914657,31.088052',3,0,'2026-04-03 12:59:01','2026-02-24 06:56:15'),(21,'重庆','云阳龙缸风景区','重庆市云阳县清水乡','云阳龙缸风景区，国家5A级旅游景区、国家地质公园，集天坑、峡谷、溶洞、高山草场、森林、土家风情于一体，主要景点有龙缸天坑、云端廊桥、龙洞风光、蔈草古长城、岐阳关古道遗址、盖下坝湖泊等。云端廊桥犹如天空之花的云端廊桥建在海拔1010米高的悬崖上悬崖垂直高度718米，悬挑长度26.68米，比美国科罗拉多大峡谷玻璃廊桥悬挑长度还高5米多，堪称世界第一。','120元','http://store.is.autonavi.com/showpic/a82dcd03afe029dd7739f52d78c9ed2d?type=pic,http://store.is.autonavi.com/showpic/4cab1132df38233170560a23aaa88cf1?type=pic,http://store.is.autonavi.com/showpic/fe17689ead654c94b93981bb3512f687?type=pic','109.013669,30.676108',4,0,'2026-04-24 19:44:14','2026-02-16 05:52:25'),(22,'重庆','南川金佛山景区','重庆市南川区三汇镇汇星村','金佛山融山、水、林、泉、洞为一体，集雄、奇、险、秀于一身，春赏高山杜鹃、夏享避暑天堂、秋观层林尽染、冬品南国雪原，是四季皆宜的旅游精品，参禅拜佛的佛教圣地。金佛山，国家5A级景区、国家重点风景名胜区、世界自然遗产，由金佛、箐坝、柏枝三山108峰组成，位于重庆南部南川市境内。','150元','http://store.is.autonavi.com/showpic/aedb15f9cbb43a8ed1d57c4fc0227f02?type=pic,http://store.is.autonavi.com/showpic/4f417572087fd9fac60ef0ae44242715?type=pic,http://store.is.autonavi.com/showpic/21afe2d0fba902ca8245410c601e14d5?type=pic','107.169191,29.057957',3,0,'2026-01-10 18:09:23','2026-01-31 01:09:42'),(23,'重庆','万盛黑山谷景区','重庆市万盛区黑山镇境内','黑山谷，国家5A级旅游景区，国家级森林公园，国家级地质公园，位于万盛区景星乡境内，这里山高林密、溪河纵横、人迹罕至，保存着地球上同纬度为数不多的亚热带和温带完好的自然生态，森林覆盖率达97%。','淡季(11月1日至次年2月底)60元，旺季(3月1日至10月底)100元。','http://store.is.autonavi.com/showpic/441536d14988aacd0a462b7045b0433d?type=pic,http://store.is.autonavi.com/showpic/d9f374921dcc290f99745439fe2d03cd?type=pic,http://store.is.autonavi.com/showpic/90f9eec8b20318774e7a7a0e65e26425?type=pic,http://store.is.autonavi.com/showpic/4ef83a4a2ea90700964cc59b321dfc6d?type=pic','106.996149,28.881146',4,0,'2026-01-01 23:20:20','2026-02-04 17:12:35'),(24,'上海','外滩','海市黄浦区中山东一路','位于上海市中心黄浦区的黄浦江畔，是最具上海城市象征意义的景点之一。长1.5公里，由南向北漫步，左手边是宽阔的中山东一路，路边一字排开着数十栋风格迥异的外国建筑。紧靠上海的母亲河—黄浦江，江上巨轮穿梭，江对岸则矗立着金茂大厦、环球金融中心等摩天建筑。夜晚，浦江两岸霓虹齐放，适合与爱人漫步在外滩，感受着“不夜城”的韵味与浪漫。','免费','https://iknow-pic.cdn.bcebos.com/060828381f30e9244db7b1a542086e061d95f717','121.492156,31.233462',4,0,'2026-02-20 16:01:55','2026-01-30 04:31:51'),(25,'上海','上海迪士尼乐园','上海市浦东新区川沙新镇黄赵路310号(迪士尼地铁站1号口步行360米)','上海迪士尼乐园是中国内地首座迪士尼主题乐园，欢迎来到一个前所未见的神奇世界。乐园分为米奇大街、奇想花园、梦幻世界、探险岛、宝藏湾、明日世界和迪士尼·皮克斯玩具总动员七大主题园区。乐园内拥有世界上最大的迪士尼城堡“奇幻童话城堡”，游客可以在乐园内与众多迪士尼朋友互动，感受独特的沉浸式体验。建议提前下载上海迪士尼度假区官方APP，查看乐园地图、等候时间、项目及演出时间、领取FP等。','450元','https://iknow-pic.cdn.bcebos.com/b17eca8065380cd7c0e79d79af44ad34588281ac','121.667003,31.141447',2,0,'2026-04-24 22:33:30','2026-01-03 03:11:59'),(26,'上海','上海野生动物园','上海市浦东新区南六公路178号','上海野生动物园是集野生动物饲养、展览、繁育保护、科普教育与休闲娱乐为一体的主题公园。景区于1995年11月18日正式对外开放，地处上海浦东新区，占地153公顷（约2300亩），是首批国家5A级旅游景区。园区居住着大熊猫、金丝猴、金毛羚牛、朱鹮、长颈鹿、斑马、羚羊、白犀牛、猎豹等来自国内外的珍稀野生动物200余种，上万余只。园区分为车入区、步行区及“水域探秘”三大游览区域。','130元','https://iknow-pic.cdn.bcebos.com/dbb44aed2e738bd44ad88da5af8b87d6267ff9ad','121.721793,31.055337',5,0,'2026-01-29 20:19:25','2026-01-18 20:01:10'),(27,'上海','田子坊','上海市黄浦区泰康路200-1号上海旅游咨询服务近','由上海最具特色的石库门里弄演变而来，位于浦西，堪称很小资的地点之一。名字是画家黄永玉起的雅号，个性、文艺的年轻人初到上海定奔此地，感受田子坊与众不同的个性。走在田子坊，迂回穿行在迷宫般的弄堂里，特色小店和艺术作坊不经意间跳入视线。从茶馆、露天餐厅、露天咖啡座、画廊、家居摆设到手工艺品，以及众多沪上知名的创意工作室应有尽有。','免费','https://iknow-pic.cdn.bcebos.com/2e2eb9389b504fc28b3a9c91ebdde71190ef6d38','121.468662,31.208197',4,0,'2026-01-03 15:07:35','2026-03-21 15:34:24'),(28,'上海','南京路步行街','上海市黄浦区南京东路558号','全国十大著名步行街之一，是上海开埠后最早建立的一条商业街。这里是百货公司的聚集地，商品类目齐全，是购物者的天堂。随处可见富有创意的城市雕塑，街中央还有大量椅子供游客小坐，文艺时尚气息十足。南京路步行街上，可以看到像缩小版旧式电车的铛铛车穿梭往来，很有老上海的味道，不妨体验一下。','88元','https://iknow-pic.cdn.bcebos.com/fc1f4134970a304eaa7b8c6edfc8a786c8175ccc','121.479494,31.235983',3,0,'2026-01-31 08:29:18','2026-02-02 19:43:16'),(29,'上海','上海城隍庙旅游区','上海市黄浦区方浜中路249号','城隍庙旅游区包含了老城隍庙、豫园及购物美食小商品等一大块区域，是很多人来上海必游的景点。“豫园”和“老城隍庙”是明代私人园林与道教道观，需购票游览，其他区域基本都是开放性的景点。夜幕降临时，整个步行街会变得更加金碧辉煌，喜欢摄影的蜂蜂一定不能错过。对于初访上海的游客而言，城隍庙是全面地领略上海历史、文化、风情，并品尝到地道的上海小吃的第一窗口。','10元','https://iknow-pic.cdn.bcebos.com/a5c27d1ed21b0ef4da1da8cad3c451da80cb3ea8','121.492466,31.225879',5,0,'2026-03-15 01:08:30','2026-01-27 18:32:41'),(30,'上海','朱家角古镇','上海学市青浦区朱家角镇课植园路4555号','俗称“角里”，离上海最近的江南水乡古镇，是上海四大历史文化名镇之一。镇内小桥流水，古意盎然，展现出江南水乡的缩影。最出名的放生桥是上海地区最大的一座五孔联拱石桥。北大街很多特色小吃店，有著名的阿婆粽，还有各种精致的糕点都可以在这里吃到。','免费','https://iknow-pic.cdn.bcebos.com/9e3df8dcd100baa161d7782f4910b912c9fc2eae','121.053906,31.115379',5,0,'2026-02-04 17:17:55','2026-04-04 06:51:33'),(31,'上海','陆家嘴','上海市浦东新区','陆家嘴位于浦东新区的黄浦江畔，与外滩隔江相对，国内外首屈一指的金融商圈，现在已是上海最具魅力的地方。汇集了东方明珠、上海国际会议中心、环球金融中心等高楼大厦，林立的摩天大楼让人仿佛置身于一片城市森林。晚间，站在高楼大厦之上，俯瞰灯火辉煌的夜景，会更高感受到一线城市的现代感。这里是时尚达人聚集的地方，各种国际大牌，购物的好去处。','免费','https://iknow-pic.cdn.bcebos.com/ae51f3deb48f8c54ffa7eabb34292df5e0fe7f29','121.5025,31.237015',4,0,'2026-01-03 06:24:02','2026-04-02 11:25:31'),(32,'福建','湄洲岛国家旅游度假区','莆田市秀屿区湄洲镇湄洲岛','莆田市第二大岛，素有“南国蓬莱”美称。湄洲岛具有得天独厚的滨海风光和自然资源，天空、大海、阳光、沙滩汇聚于此，让旅客流连忘返。妈祖庙，每年妈祖的诞辰，这里就会变得特别热闹。','65元','https://pic4.zhimg.com/80/v2-d1c477cac4f61e373ea95593b45ef253_1440w.webp,https://pic4.zhimg.com/80/v2-88bdb379c1194161c576f84ff0744f1f_1440w.webp','119.128483,25.063753',3,0,'2026-04-01 13:55:31','2026-02-28 11:21:00'),(33,'福建','东山岛','漳州市东山县357国道','东山岛是福建省著名的风景名胜区之一，这里海湾辽阔，沙滩平缓，绿树成荫，胜景众多，极具南国滨海风光特色。 岛上比较著名的乌礁湾是当地特别保护渔湾，以自然美著称，马銮湾则以新开发的海滨浴场闻名。','免费','https://pic1.zhimg.com/80/v2-f2df93c3826e2ccdbd2c55f05c6c45a0_1440w.webp,https://pic2.zhimg.com/80/v2-1ca978b2170ff3b03b6f3fac31af1e59_1440w.webp','117.531382,23.734146',3,0,'2026-01-21 14:58:30','2026-02-17 16:49:30'),(34,'福建','泰宁大金湖','三明市泰宁县大金湖世界地质公园内','金湖是一个人工湖，这里属于丹霞地貌，山石呈赤红色。阳光照射下，红得更鲜明。','183元','https://pic3.zhimg.com/80/v2-90230ed260ca7ea7cefa195f17f2fb8e_1440w.webp,https://pic2.zhimg.com/80/v2-10e0058143ced851a53c10b1fe7f908d_1440w.webp','117.061712,26.860906',4,0,'2026-02-26 15:12:01','2026-01-21 01:31:36'),(35,'福建','白水洋','宁德市屏南县235国道','白水洋是鸳鸯溪五大景区中最具特色的天然景观，平坦的岩石河床一石而就，净无沙烁，登高俯瞰，其形状犹如一丘刚刚耙平的巨大农田，平展展地座落在崇山峻岭之中，因而当地人称“仙耙溪”。','免费','https://pic4.zhimg.com/80/v2-b0bc20403be50a29ec2710c7c1f57fdb_1440w.webp,https://pic2.zhimg.com/80/v2-061de9afef567a6203df4109b3309dc1_1440w.webp','119.077194,27.091849',5,0,'2026-02-20 10:01:57','2026-03-13 21:34:57'),(36,'福建','三坊七巷','福州市鼓楼区文儒坊6号','由三个坊、七条巷和一条中轴街肆组成，因此自古就被称为“三坊七巷”。 区域内都是窄窄的小巷，白墙瓦屋、坊巷纵横，石板铺地，每个坊巷口都有一个石刻的牌楼。','48元','https://pic3.zhimg.com/80/v2-3379b831c5a47e0ab91bc612f988f16e_1440w.webp,https://pic4.zhimg.com/80/v2-3318e67e558730cc6164b83bccd6feeb_1440w.webp','119.296623,26.081958',3,0,'2026-03-30 05:48:56','2026-04-16 12:19:48'),(37,'福建','永定土楼','龙岩市永定区湖坑镇洪坑','是国家5A级景区、世界文化遗产，也被戏称为“中国古建筑的一朵奇葩”。景区主要由洪坑土楼群、高北土楼群、初溪土楼群、南溪土楼群、中川古村落等组成。有圆楼、方楼、等各式土楼，现存土楼4000多座，被称为“一座没有大门的中国客家土楼博物馆”。','65元','https://pic1.zhimg.com/80/v2-a849cf88ac951c05e7142806bc4681e4_1440w.webp,https://pic1.zhimg.com/80/v2-988b41a92599f23e9bc6d7dde128b9d4_1440w.webp','116.97428,24.651166',4,0,'2026-01-23 20:12:15','2026-02-07 16:01:52'),(38,'福建','太姥山','宁德市福鼎市太姥山镇竹下村坑头1号','以花岗岩峰林岩洞为特色，融山、海、川和人文景观于一体的风景区。雄峙于东海之滨，晴川海畔，山海相依，傲岸秀拔，气势恢宏，景致独特，素以“海上仙都”著称。','140元','https://pic3.zhimg.com/80/v2-0cedf9d2b69c7b2f0789ccf801b2911e_1440w.webp,https://pic2.zhimg.com/80/v2-d53016b083ebb0a0a70846f020d4da29_1440w.webp','116.433053,39.912439',5,0,'2026-04-30 19:32:36','2026-01-07 01:37:24'),(39,'福建','武夷山','南平市武夷山市303省道','它是三教名山，也有“福建第一山”的美誉。武夷山风景区位于武夷山脉的中部、福建省武夷山市境内，方圆60平方公里，盘曲山中的长约9公里的九曲溪和夹崖森列的36峰，构成一幅碧水舟山的天然美景。九曲溪是武夷山脉主峰——黄岗山西南麓的溪流，位于福建省武夷山峰岩幽谷之中。因有三弯九曲之胜，故名为九曲溪。九曲溪从西向东，蜿蜒自如，可谓曲曲含异趣，湾湾藏佳景','120元','https://pic1.zhimg.com/80/v2-56cd646c8d94f0ffa53a4c3069c55d18_1440w.webp,https://pic2.zhimg.com/80/v2-270a376c78af5d5c234072deb406a8c5_1440w.webp,https://pic1.zhimg.com/80/v2-b0506956015ca2b6dc282c85bad4475c_1440w.webp,https://pic3.zhimg.com/80/v2-1317369320a5547d54fd0b910d4febc6_1440w.webp','117.959681,27.656446',2,0,'2026-01-31 21:29:11','2026-01-17 06:33:45'),(40,'辽宁','金石滩','辽宁省大连市金州区龙谷街','金石滩是一处集低山丘陵、海蚀地貌、海滨风光等自然景色以及现代人文景观于一体的，以滨海度假、体育休闲、商务娱乐、海滨游览观光、地质科考等为主要内容的海滨型国家级风景名胜区。金石滩景区陆地面积70.34平方公里，海域面积58平方公里，海岸线30多公里，冬暖夏凉，凝聚了3-9亿年地质奇观，形态各异，巧夺天工，被称为“凝固的动物世界”、“天然地质博物馆”。','免费','http://store.is.autonavi.com/showpic/518ab0bdb4401f1c8a3b9dec8d2874c1?type=pic,http://aos-cdn-image.amap.com/sns/ugccomment/57dea967-eb5f-4247-8cdf-8793b179649a.jpg?type=pic,https://aos-comment.amap.com/B0FFFDRUZH/headerImg/0fb25d6ad93440fb1a640d510b3bb10b_2048_2048_80.jpg?type=pic','122.0156,39.079789',5,0,'2026-04-19 16:21:11','2026-01-15 14:04:43'),(41,'辽宁','大连老虎滩海洋公园-老虎滩极地馆','辽宁省大连市中山区滨海中路9号','老虎滩海洋公园坐落于辽宁省大连市南部海滨中部，占地面积118万平方米，有着4000余米的曲折海岸线，是中国规模较大的一座现代化海滨游乐场。大连老虎滩海洋公园是滨城一道亮丽的风景，每年接待海内外游客200多万人次，它是中国旅游知名品牌。老虎滩海洋公园是展示海洋文化，突出滨城特色，集观光、娱乐、科普、购物、文化于一体的现代化主题海洋公园。','190元','http://store.is.autonavi.com/showpic/279d3d6af168133da4a6caa555d17010?type=pic,http://store.is.autonavi.com/showpic/8f5fe7fc88145e40db3520386807c587?type=pic,http://store.is.autonavi.com/showpic/06ac994784ed03974893190eb7013b24?type=pic','121.677169,38.878242',4,0,'2026-04-17 21:20:02','2026-01-11 16:26:04'),(42,'辽宁','大连星海广场','辽宁省大连市沙河口区中山路572号','大连星海广场，位于辽宁省大连市沙河口区，是纪念香港特别行政区回归中国的主要建设工程，也是大连市的标志建筑之一。星海广场总占地面积为176万平方米，地面上层中间设三条圆形道路，将广场分为三个景观层次；广场长轴有两条平行道路贯穿广场，与之相交叉的另外有两条成X形的道路，分割成六个部分；星海广场景观分为四个部分：星海广场、喷泉景区、百年城雕广场及中央草坪。','免费','http://store.is.autonavi.com/showpic/dcac6bba31dfa3d8e8511f9b192d6941?type=pic,http://store.is.autonavi.com/showpic/5d5d99e4a143efd7220db008d92ef947?type=pic,http://store.is.autonavi.com/showpic/f0255a7d2d5a486a62b9dd813d49d54f?type=pic,http://store.is.autonavi.com/showpic/2a55654d690c449665fdbd758b94d272?type=pic','121.587922,38.882006',3,0,'2026-04-03 18:10:13','2026-03-13 17:32:53'),(43,'辽宁','本溪水洞景区','辽宁省本溪市本溪满族自治县谢家崴子村','本溪水洞风景名胜区位于辽宁省本溪市东郊，是以岩溶洞穴、地下暗河为主，集山、水、洞、泉、湖、林于一体的自然景观景区，被中国《国家地理》杂志评为“中国最美的旅游洞穴\"，被国家建设部评为“中国最具潜力的十大风景区\"之一。本溪水洞现开发地下暗河长3000米，水流终年不竭，清澈见底，洞顶和岩壁钟乳石发育较好，千姿百态，泛舟游览，使人流连忘返，被赞誉为“钟乳奇峰景万千，轻舟碧水诗画间；钟秀只应仙界有，人间独一此洞天”。','70元','http://store.is.autonavi.com/showpic/9ad920be0f88f3317db34172bb6f7e92?type=pic,http://store.is.autonavi.com/showpic/ec23cb07b2f1029203673fe3082d8c76?type=pic,https://aos-comment.amap.com/B019E00LBV/headerImg/9fbd9fb9b60b624263e066890cc5f8fa_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/a8effaaff7990e82eb4e78cb9b248200?type=pic','124.080348,41.300153',5,0,'2026-03-22 09:13:47','2026-03-08 17:30:18'),(44,'辽宁','千山风景区','辽宁省鞍山市铁东区千山东路79号','千山，古称积翠山，因有九百九十九座山峰，遥望若青莲接天而得名，素有“东北明珠”之誉，是国家重点风景名胜区。千山风景区总面积125平方公里，以峰秀、石峭、谷幽、庙古、佛高、松奇、花盛而著称，具有景点密集、步移景异、玲拢剔透的特色。除此之外，千山宗教文化厚重，佛道共融一山，是东北颇大的宗教聚集之地，有龙泉寺、祖越寺、香岩寺、中会寺、大安寺和无量观、五龙宫等“九宫、八观、五大禅林、十二茅庵”，近40座庙宇。','60元','http://store.is.autonavi.com/showpic/e1d44225d3e43e70ced492990380ba67?type=pic,https://aos-comment.amap.com/B019C013EW/headerImg/6d27bae8b9c41a59db970c5ac7249bae_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/9677d9eac687da001a1402935af94d57?type=pic','123.126478,41.013578',4,0,'2026-04-03 11:50:07','2026-01-23 06:39:45'),(45,'辽宁','沈阳故宫博物院','辽宁省沈阳市沈河区沈阳路171号','沈阳故宫博物院位于辽宁省沈阳市沈河区沈阳路171号，始建于1625年，是清代初期营建和使用的皇家宫苑。沈阳故宫占地面积六万多平方米，有古建筑114座，500多间，至今保存完好，是中国目前仅存的较为完整的两大古代宫殿建筑群之一，其作为明清皇宫文化遗产扩展项目列入《世界文化遗产名录》。在宫廷遗址上建立的沈阳故宫博物院是著名的古代宫廷艺术博物馆，藏品中包含十分丰富的宫廷艺术品。','60元','http://store.is.autonavi.com/showpic/490ba0defe5b861103faace12550d07e?type=pic,http://store.is.autonavi.com/showpic/20f42f8b95eb36b3d4e89fef559c01b3?type=pic,http://store.is.autonavi.com/showpic/ef644ad09ae994ed55cc7f80a6593acf?type=pic,http://store.is.autonavi.com/showpic/a6bdac55e5b4d31ba5be92993c2e310e?type=pic','116.397029,39.917839',4,0,'2026-03-15 21:48:26','2026-03-04 17:02:53'),(46,'辽宁','鸭绿江国家风景名胜区','辽宁省丹东市宽甸满族自治县','丹东鸭绿江游览区位于鸭绿江中心下游丹东市境内，东起浑江口，西至大东港，全长210公里，总面积824.2平方公里（含中朝共管水面），保护区面积200平方公里。鸭绿江流径丹东市约300公里，此段江面宽阔，两岸风光秀丽，在入海口一带，盛产大银鱼。鸭绿江古称坝水，汉称为訾水，唐朝始称鸭绿江，因其水色青绿、恰如鸭头而得名。鸭绿江发源于吉林省长白山南麓，流经长白、集安、宽甸、丹东等地，向南注入黄海，全长795公里，是中朝两国的界河。','5元','http://store.is.autonavi.com/showpic/dd3a38c8ad91028707fea6f0cf34b235?type=pic,http://store.is.autonavi.com/showpic/c264a1d5a891a22d1b8231b4c75d40cf?type=pic,http://store.is.autonavi.com/showpic/e32d22498ea04ceec039d08d7a404ef5?type=pic,http://store.is.autonavi.com/showpic/1e01cce5d8e33672198c71183bd19a69?type=pic','124.397586,40.122956',3,0,'2026-04-02 19:49:09','2026-01-31 23:57:06'),(47,'辽宁','抗美援朝纪念馆','辽宁省丹东市振兴区山上街7号','抗美援朝纪念馆，建立于1958年10月，位于辽宁省丹东市鸭绿江畔的英华山上，与朝鲜民主主义人民共和国新义州市隔江相望。纪念馆是中国建成开放的一座全面反映中国人民抗美援朝战争和抗美援朝运动历史的专题纪念馆，先后荣获国家AAAA级旅游景区、全国中小学生研学实践教育基地等荣誉称号。纪念馆园区总占地面积18.2万平方米，由纪念馆、纪念塔、全景画馆、国防教育园组成，馆藏抗美援朝文物2万余件。','免费','http://store.is.autonavi.com/showpic/5429a6268650aaf5b9214f6a2a7229c8?type=pic,http://aos-cdn-image.amap.com/sns/ugccomment/8c5e6070-b18c-4875-aa56-fa60b2220f90.jpg?type=pic,','124.364745,40.119074',5,0,'2026-04-30 12:18:06','2026-01-25 13:39:11'),(48,'河北','承德避暑山庄','河北省承德市双桥区丽正门路的20号','承德避暑山庄，以及周围庙宇景观，是初到河北必打卡的景点之一，现为世界文化遗产，与国家5A级景区，是一处皇家园林，院内的许多处小园林，是模仿江南园林的而建，山庄内有处博物馆，是整个园林的人文历史景观，这里需要二次检票，在山庄周围，有众多寺庙景观，有着小布达拉宫之称-普陀宗乘之庙，千手千眼观世音菩萨-普宁寺等寺庙景观。','90元','http://store.is.autonavi.com/showpic/52b4fd748b8b703c076b0d4123c15001?type=pic,http://store.is.autonavi.com/showpic/a51a8e7d777f273a8fbf317106829e34?type=pic,http://store.is.autonavi.com/showpic/d5df9e0b23856c42435eab39ee5d583c?type=pic','117.934794,40.995449',4,0,'2026-01-05 07:21:40','2026-03-09 19:50:47'),(49,'河北','娲皇宫','河北省邯郸市涉县的中皇山','娲皇宫，是我国建筑规模最大，时间最早的祀奉始祖女娲的古建筑群，被誉为华夏祖庙，现为国家5A级旅游景区，为涉县古八景之一，景点有补天园-补天湖-娲皇宫等几个园区组成，景区人文景观浓厚，并留有北齐佛教石刻，唐代题记与宋代砖墙，元代石雕和明清建筑等文物珍品，而最为著名则是景区内摩崖刻经，天下第一壁经， 有13.7万多字，面积达65平方米。','免费','http://store.is.autonavi.com/showpic/897bf6ad513c3a4fcea91b07cd45d63e?type=pic,http://store.is.autonavi.com/showpic/90d81d2de521e2b26015623e33656535?type=pic,http://store.is.autonavi.com/showpic/3bdac3e3556a2c1c5f57a40a0c12c817?type=pic','113.618874,36.639939',5,0,'2026-03-28 05:08:57','2026-04-18 14:12:26'),(50,'河北','涞水野三坡','河北省保定市涞水县太行山与燕山两大山脉的交汇处','野三坡，是北方地区著名的旅游胜地，现为国家5A级旅游景区，这里有奇特自然风光，纯净生态环境，古老的历史，浓郁的民族风情丰富多彩，景区由百里峡-白草畔-鱼谷洞-龙门天关等景点组成，而百里峡，是野三坡的精华所在，白草畔，以高山森林，最出名的是冰川杜鹃，野三坡景区，以其独特的魅力，深受海内外游人的青睐，还被誉为世外桃源，无处体现着大自然的鬼斧神工。','25元','http://store.is.autonavi.com/showpic/ec97ccd4a13f8b75c0732ab12625ab4e?type=pic,http://store.is.autonavi.com/showpic/f584411dc624466e4a90a4adfcc46c34?type=pic,http://store.is.autonavi.com/showpic/39ab223d67552ea6008dff641a2ad3c5?type=pic','115.385583,39.668405',3,0,'2026-02-09 07:35:18','2026-04-24 19:19:11'),(51,'河北','西柏坡景区','河北省石家庄市平山县西柏坡镇西柏坡纪念馆的东侧路','西柏坡红色革命旧址，现为国家5A级旅游景区，位于平山县境内，与江西井冈山-江西瑞金-贵州遵义-陕西延安为我国的五大革命圣地，西柏坡旧址，是由中共中央旧址，西柏坡纪念馆，西柏坡纪念碑等多处景点组成。','免费','http://store.is.autonavi.com/showpic/7f7cecd0b82c89f8a385505b37361720?type=pic,http://store.is.autonavi.com/showpic/9bc14781c52abd63956b0cc5ce7601db?type=pic','113.954368,38.352405',5,0,'2026-04-02 01:50:05','2026-04-24 23:12:53'),(52,'河北','白洋淀','河北省保定市与沧州市的交界处','白洋淀是河北地区一处湖光风色非常好看的风景名胜区，这座风景名胜区的位置位于河北省保定市与沧州市的交界处，这座湖泊是由143个相互交连的大小淀泊联合组建而成的，是我国的国家5A级风景名胜区。','40元','http://store.is.autonavi.com/showpic/0e3c19acbccc8e745d6178f6a3721b22?type=pic,http://store.is.autonavi.com/showpic/66b86733b75963a31c40f9b35a1f358b?type=pic,http://store.is.autonavi.com/showpic/7a6a91363595f03c87ffe0f5d5647166?type=pic','116.002575,38.934609',4,0,'2026-02-26 14:34:09','2026-03-03 03:12:07'),(53,'河北','清东陵','河北省唐山市遵化市的西北30公里处','清西东陵，是清朝皇帝的陵寝，两陵距离约近300公里，清东陵位于唐山市遵化市，共有皇陵五座，其中顺治的孝陵，康熙的景陵，乾隆的裕陵，咸丰的定陵与同治的惠陵，包括皇后嫔妃等陵墓，当年，东陵大盗孙殿英，就盗取于此陵，清西陵景区，位于保定市易县，共有皇帝陵四座，雍正的泰陵，嘉庆的昌陵，道光的慕陵与光绪的崇陵，包括皇后嫔妃等陵墓，是清朝时期，最后的一处帝王陵墓群，清西东陵，均为国家5A级旅游景区，世界文化遗产。','110元','http://store.is.autonavi.com/showpic/7a623089df7320ea4501dc405311a884?type=pic,http://store.is.autonavi.com/showpic/57acde50102972840e140dd172152a17?type=pic,http://store.is.autonavi.com/showpic/ef36445ffbb82feaaad8c9d1aec0a010?type=pic','117.6827,40.173542',5,0,'2026-01-16 20:18:07','2026-01-16 19:54:16'),(54,'河北','广府古城','河北省邯郸市永年区广府镇的广府专线内','广府古城，距今已有2600多年历史，是北方地区唯一的早地水城，古城建筑主要建于明代年间，现为国家5A旅游景区，其实，广府古城，只是保留了城墙，周围被护城河包围，在华北平原，像这种古城很少见，这里是太极拳宗师的故乡，城南门外，有杨式太极拳杨露禅的故居，城内有武式太极拳创始人武禹襄的故居，对于酷爱历史文化的驴友，这里非常值得前去打卡。','80元','http://store.is.autonavi.com/showpic/0b93ec6be60d70c741161d5b87d0822b?type=pic,http://store.is.autonavi.com/showpic/f9f28d2ae4514a7c5b8545bdc67c14c8?type=pic,http://store.is.autonavi.com/showpic/0b93ec6be60d70c741161d5b87d0822b?type=pic','114.730269,36.700889',2,0,'2026-02-01 14:37:01','2026-04-21 13:22:19'),(55,'河北','山海关-老龙头景区','河北省秦皇岛市的东北15千米处','老龙头与天下第一关，均在山海关区域，但为两个景点，而两个景点相距远，但有公交直达景区，虽然之前被摘掉5A级景区牌面，但在2018年又恢复，老龙头是山海关景区的一部分，也是万里长城的最东段，沿伸于渤海湾，天下第一关，也是山海关景区的部分之一，是山海关古城的所在地，是长城东段的第一所关卡，两个景点均可单独购票。','20元','http://store.is.autonavi.com/showpic/1491eee0cd6a82333e8c90174352e28a?type=pic,http://store.is.autonavi.com/showpic/984d541bbf373d97fe3f32b9815f8ee7?type=pic,http://store.is.autonavi.com/showpic/b512cb88af6207903654760d07140f84?type=pic','119.797684,39.968483',3,0,'2026-04-08 23:00:30','2026-02-08 02:55:36'),(56,'云南','丽江古城','丽江市古城区大研街道民主路和长水路交汇处','丽江古城又名大研镇,是茶马古道上最著名的城镇之一,已有八百多年的历史。古城内木楼青瓦,古街石巷,小桥流水,站在古城东大街上,举头即可遥望玉龙雪山。《一米阳光》、《木府风云》等影视剧都在此取过景。','免费','http://store.is.autonavi.com/showpic/8cddcf00e57f7bf52fe79fe3b0df2a4f?type=pic,http://store.is.autonavi.com/showpic/45a338030abb51e6cf184daf7841104d?type=pic,http://store.is.autonavi.com/showpic/5b2e42aad834d588fca4fbf329832c93?type=pic','100.235517,26.870507',3,0,'2026-01-17 17:36:30','2026-03-31 07:15:44'),(57,'云南','洱海','大理白族自治州大理市洱河南路1号','洱海公园位于大理市区北侧,紧靠洱海,是一个沿湖的城市公园,风光清新优美,交通便利,是很多游客到达大理接触洱海的第一站。公园内有一座小山,步行到山顶可以远望洱海美景,还可以俯瞰城区风光。公园原名团山公园,园中的小山就是团山,曾经是南诏国王养鹿的地方。小山不高,大约爬200多级台阶就可以登顶,山的周围树木茂密,因此也成了本地市民晨练、散步的热门去处。','免费','http://store.is.autonavi.com/showpic/9ad763929dd16f4a52585b7f05c77136?type=pic,https://aos-comment.amap.com/B0368006Y0/headerImg/db040ffc43b47ec2eff56dd4a47a7b98_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/e3f0833992854e5a99762606b0e6d275?type=pic','100.247369,25.603036',4,0,'2026-02-06 07:29:12','2026-02-03 15:38:46'),(58,'云南','大理古城','大理白族自治州大理市一塔路42号','大理古城景区位于云南省的中西部。唐宋时曾先后在此建为地方政府“南诏国”和“大理国”。现在大理还保存着一小段古城墙。大理古城尚存有很多古建筑物,象征大理的三塔,就建于二千多年的南诏丰佑年间,三塔成鼎足形,雄伟壮观。还有南诏国的发祥地巍宝山、佛教胜地鸡足山、石宝山窟、小普陀、天镜阁、南诏德化碑、南诏铁柱。 在大理古城景区西北1公里处,就是被国务院列为全国第一批重点文物保护单位的大理三塔,与古城西南角的弘圣寺一塔遥遥相对,为古城增添了一层灿烂的色彩。 大理古城景区的城区道路仍保持着明、清以来的棋盘式方格网结构,素有九街十八巷之称。南北对峙的两座城楼被修复一新。','免费','http://store.is.autonavi.com/showpic/b67bc104ecc75ecaa12b1cb794301f98?type=pic,http://store.is.autonavi.com/showpic/e2e7dda99ba01e304b522ba642fb2994?type=pic,http://store.is.autonavi.com/showpic/8d4e6b05a887be32d9ad2052cce88c69?type=pic','100.164,25.694836',5,0,'2026-03-01 07:46:17','2026-03-17 15:55:05'),(59,'云南','双廊古镇','大理白族自治州大理市S314(环海东路)','双廊镇位于云南省大理市东北端,洱海东北岸,是云南省省级历史文化名镇和“苍洱风光第一镇”。其面积218平方千米,位居大理市第二位,常住人口18890人(2017年),双廊镇地处东经100˚11˝,北纬25˚53˝。大理市是中国最佳魅力城市、国家级历史文化名城、国家风景名胜区、国家级自然保护区、全国优秀旅游城市,是国家4A级旅游景区“南诏风情岛”所在地。镇域三面环山,一面临海。西跳苍山十九峰,门临洱海万倾碧波,东靠“佛教胜地”鸡足山,南接“蓬莱仙岛”小普陀。','免费','http://store.is.autonavi.com/showpic/4317bf329ac2c3eef14a555c754fcb28?type=pic,http://store.is.autonavi.com/showpic/3873c69e48be6d02e47de353e35ae487?type=pic,http://store.is.autonavi.com/showpic/37cf020f5c7d20ace53246a29f39ad8b?type=pic','100.194322,25.908323',4,0,'2026-03-22 08:16:37','2026-02-24 17:37:49'),(60,'云南','玉龙雪山','丽江市玉龙纳西族自治县','玉龙雪山是纳西族神山，也是去丽江必玩景点。玉龙雪山的最高海拔为5596米， 玉龙雪山冰川公园的最高海拔为4680米，也是大家到玉龙雪山景区所能到达的最高海拔。','免费','http://store.is.autonavi.com/showpic/89f1a591189babe3a067ab90fd71023b?type=pic,http://store.is.autonavi.com/showpic/87d2213e4a284f90085d3b796ac208d8?type=pic,http://store.is.autonavi.com/showpic/76576e2f29ece739f7c5a35db469f2dd?type=pic,http://store.is.autonavi.com/showpic/08e24892a83a275966ce0ab135e9c787?type=pic','100.210679,27.129447',3,0,'2026-02-02 15:19:15','2026-04-29 23:42:48'),(61,'云南','花语牧场','大理白族自治州大理市仁里邑村','大理苍洱间最美的花海名园,花语牧场在大理喜洲镇,很大的一片花的海洋,这里有大理唯一的紫罗兰花海,一望无际的花海,仿若人间仙境,彩蝶纷飞,蜜蜂起舞,一个个忙碌而又欢快的精灵,在花丛间穿梭往来,处处充满了一种奔放、自由和令人沉醉神往的勃勃生机!一阵阵的幽香环绕着你的身周,挑逗你的味蕾,直至沁人心脾!','免费','http://store.is.autonavi.com/showpic/22b8e891bb91f8ddc6633f80a158a44f?type=pic,http://store.is.autonavi.com/showpic/2a51ae5f00f57aa71e3a25ba96f15bec?type=pic,http://store.is.autonavi.com/showpic/1261ea304fdce0c5484d696f364d6b05?type=pic','100.121648,25.891901',5,0,'2026-01-18 00:36:16','2026-03-30 03:52:58'),(62,'云南','滇池海埂公园','昆明市西山区滇池路1318号','海埂公园位于滇池的东畔,是一处风光秀美的公园,也是滇池的主要观赏地。这里沿湖绿树婆娑,搭配了橙黄色的步道,各种色彩鲜亮的雕塑,环境清新优美。海埂顾名思义,就是指深入滇池中的一道长堤,这条堤坝把滇池分成了两片湖泊。如今堤坝两侧种植了草坪,沿着堤坝到湖中游览观光感觉十分不错。每年冬天,滇池都是红嘴鸥栖息的乐园,届时在公园里喂鸟观鸟更是昆明市民的一项热门活动。海埂公园内可以烧烤,需提前电话咨询预约。','免费','http://store.is.autonavi.com/showpic/9c7d5d7ceb7f6c6781cf9bfec3b3938a?type=pic,http://store.is.autonavi.com/showpic/20fb20396757d387cf4099d4179d605f?type=pic,https://aos-comment.amap.com/B036702E39/headerImg/794313c9736ea7f625474c6584b4fa45_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/d25465f211b735e98856a7b80bd22c9f?type=pic','102.659487,24.960029',5,0,'2026-01-30 17:36:01','2026-01-05 04:21:11'),(63,'西藏','布达拉宫','拉萨市城关区北京中路35号','布达拉宫座落在海拔3700米的西藏自治区拉萨市中心的红山上,因其建造的悠久历史,建筑所表现出来的民族审美特征,以及对研究藏民族社会历史、文化、宗教所具有的特殊价值,而成为举世闻名的名胜古迹。 据史书记载:公元七世纪三十年代,吐蕃第三十三代赞普松赞干布迁都拉萨,始建布达拉宫为王宫。当时修建的整个宫堡规模宏大,外有三道城墙,内有千座宫室。松赞干布在此划分行政区域,分官建制、立法定律、号令群臣,施政全蕃,并遣使周边各国或与邻国建成姻亲关系或订立盟约,加强吐蕃与周边各民族经济和文化交流,促进吐蕃社会的繁荣。布达拉宫成为吐蕃王朝统一的政治中心,地位十分显赫。公元九世纪,随着吐蕃王朝的解体,布达拉宫遭冷落。 公元九世纪至十七世纪中叶的800余年中,由于西藏政治中心地的不断变移,历代的萨迦、帕竹、噶玛巴政权都未曾设首府于拉萨,布达拉宫也一直未能重建,仅为拉萨大昭寺隶属的一处宗教活动场所。当时藏传佛教噶当派高僧琼布扎色、噶举派嘎玛•徳辛协巴、格鲁派始祖宗喀巴等不同教派著名人物在此举行过讲经传法等佛事活动。','200元','http://store.is.autonavi.com/showpic/386df9f5ab53cc8e27fc71a429040472?type=pic,http://store.is.autonavi.com/showpic/8e44fe9651798bc8a3bc717f21df22ea?type=pic,http://store.is.autonavi.com/showpic/08fd5780db95d782ae3f0cae4e820a51?type=pic,http://store.is.autonavi.com/showpic/8321fdd0e34c8d0ed875946b1f81a4f6?type=pic','91.118463,29.654471',4,0,'2026-02-21 16:57:53','2026-01-06 23:45:54'),(64,'西藏','大昭寺','拉萨市城关区八廓西街2号','八廓街的中心便是大昭寺,是当年松赞干布为纪念尺尊公主入藏而建。寺庙最初的名字“惹萨”后来成为这座城市的名字,并演化为今天的“拉萨”。因此,人们常说“先有大昭寺,后有拉萨城”。大昭寺作为“西藏的眼睛”,在西藏宗教文化中有着至高无上的地位,一直是各种重大佛事活动的中心,每日来此转经的人更是络绎不绝。','85元','http://store.is.autonavi.com/showpic/b5b5250e00ac670523be3b421b378f15?type=pic,https://aos-comment.amap.com/B037B00F2D/headerImg/99c546d29d72c58bd43da23a80d46401_2048_2048_80.jpg?type=pic,https://aos-comment.amap.com/B037B00F2D/headerImg/7e8faeb671c7ab261caddec4d32ca8d1_2048_2048_80.jpg?type=pic','116.390673,39.983033',4,0,'2026-04-25 19:55:53','2026-03-18 04:21:43'),(65,'西藏','色拉寺','拉萨市城关区色拉路1号','色拉寺坐落在拉萨北郊山下,是藏传佛教格鲁派三大寺之一。与哲蚌寺、甘丹寺合称拉萨三大寺,是三大寺中建成最晚的一座。 建于明永乐十七年(1419)。色拉寺藏语为“野玫园寺”。色拉寺建有一个大殿、三个扎仓(僧院)、二十九个康村。僧人最多时有5500多人。寺内保存着上万个金刚佛像,大多为西藏本地制作。还有许多是从内地或印度带来的铜佛像。大殿和各扎仓经堂四壁保存着大量彩色壁画原作。','50元','http://store.is.autonavi.com/showpic/0087b0884c37c881f58241c6399bd47a?type=pic,http://store.is.autonavi.com/showpic/4a7f52f5b1141aada87dc124a7a8e06d?type=pic,https://aos-comment.amap.com/B037B00980/headerImg/0ad25b2ed2f8521663d7cb39b23c640d_2048_2048_80.jpg?type=pic','91.134823,29.695223',3,0,'2026-02-06 10:00:57','2026-03-15 12:59:36'),(66,'西藏','纳木错','拉萨市当雄县当扎路','纳木错国家公园是拉萨首座国家公园,这是西藏继雅鲁藏布大峡谷国家公园后的第二个国家公园。位于拉萨市当雄县与那曲地区班戈县之间,面积为106万公顷,包括念青唐古拉山主峰、湖泊鸟岛、岩画石刻、羊八井等。“纳木错国家公园的挂牌标志着目前全球最先进的国家公园管理模式成功地运用于西藏旅游实践。”西藏自治区旅游局副局长孙永平说,建成后的纳木错国家公园将强化生态保护功能,逐步发展“生命繁衍之路、高原探秘之路、草甸湿地之路、藏民俗之路”等专题旅游线路。','200元','http://store.is.autonavi.com/showpic/fc4695ef14da09c7cd1c3551d709fc16?type=pic,http://store.is.autonavi.com/showpic/84dcd8d5de349f9f94373d5ee4357ab1?type=pic,http://store.is.autonavi.com/showpic/d414ee400951b496b103f82474ab7d0b?type=pic,http://store.is.autonavi.com/showpic/d7e58da83723a6bcd0387e09eba1678f?type=pic','90.888111,30.750648',4,0,'2026-01-19 10:55:08','2026-04-22 15:36:56'),(67,'西藏','羊卓雍措雅步观景台','山南市贡嘎县羊卓雍措景区内','羊卓雍错在藏语里是“碧玉湖”的意思，它的形状就像珊瑚枝一般，因此又被称为“上面的珊瑚湖”。羊卓雍错主要位于西藏山南市浪卡子县，是喜马拉雅山北麓最大的内陆湖泊，湖光山色之美，冠绝藏南。羊卓雍错与纳木错的不同之处在于纳木错适合在湖边参观，而羊卓雍错适合远观，在冈巴拉山口观景台远观羊卓雍错算人间一种极致的享受。','免费','http://store.is.autonavi.com/showpic/b1a712fef64e4871827e4cd08c530631?type=pic,http://store.is.autonavi.com/showpic/87b9d93cfadebc8abbeb0e0c14bff565?type=pic,http://store.is.autonavi.com/showpic/dd2ac72386e175ad8fc644ee001a27ad?type=pic','90.620696,29.171196',5,0,'2026-01-23 21:19:17','2026-01-20 11:45:36'),(68,'西藏','玛旁雍错','阿里地区普兰县207省道','玛旁雍错与前面介绍的纳木错、羊卓雍错一起被誉为西藏三大圣湖，位于西藏阿里地区普兰县城东35公里，是亚洲四大河流的发源地。据说玛旁雍措是最圣洁的湖，是胜乐大尊赐与人间的甘露，湖中的圣水可以清洗人心灵中的烦恼和孽障。玛旁雍错是是心灵中尽善尽美的湖，她是这个宇宙中真正的天堂，是众神的香格里拉，万物之极乐世界 。','免费','http://store.is.autonavi.com/showpic/2e20663e276b5e49f7ceab75fe6f5ca0?type=pic,http://store.is.autonavi.com/showpic/dde6a0c966e489f5caadf0642d891e54?type=pic,http://store.is.autonavi.com/showpic/814c080f68aaa0b85741211e49713938?type=pic,http://store.is.autonavi.com/showpic/23a119fcd0307a17b72bffd1bb652522?type=pic','81.370413,30.721094',5,0,'2026-01-29 18:50:12','2026-03-27 10:54:12'),(69,'西藏','珠穆朗玛峰','日喀则市定日县','每年的4月初到5月底间，是珠峰登顶的最佳时机，有许多登山人员来此驻扎，各式各样五颜六色的帐篷群散落在空旷的大本营地上，十分壮观。从风景角度考虑，4-5月的少雨季节也是观看珠峰的最佳时间，初次之外秋冬季节也是非常不错的。如果你比较追求旅游舒适度的话，可以选择在夏季的6-8月去珠峰参观。','免费','https://aos-comment.amap.com/B0FFFYYQVX/headerImg/9d7d0a6971838f4d94dceb8a152c5bb4_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/eb790dcb3a1d8175d3a77721a326d1f2?type=pic,http://store.is.autonavi.com/showpic/9ed4c73fbfe9150af7b6cc141f28cfeb?type=pic,http://store.is.autonavi.com/showpic/0089752f61e01253806dec39c6e03f9d?type=pic','86.93047,27.986914',4,0,'2026-04-11 22:00:26','2026-01-09 05:19:33'),(70,'浙江','杭州西湖','杭州市西湖区龙井路1号','西湖,位于浙江省杭州市区西面,是中国大陆首批国家重点风景名胜区和中国十大风景名胜之一。中国大陆主要的观赏性淡水湖泊之一,与南京玄武湖、嘉兴南湖并称“江南三大名湖”。西湖三面环山,面积约6.39平方千米,东西宽约2.8千米,南北长约3.2千米,绕湖一周近15千米。湖中被孤山、白堤、苏堤、杨公堤分隔,按面积大小分别为外西湖、西里湖、北里湖、小南湖及岳湖等五片水面,苏堤、白堤越过湖面,小瀛洲、湖心亭、阮公墩三个小岛鼎立于外西湖湖心,夕照山的雷峰塔与宝石山的保俶塔隔湖相映,由此形成了“一山、二塔、三岛、三堤、五湖”的基本格局。2011年6月24日,杭州西湖列入世界遗产名录。','免费','http://store.is.autonavi.com/query_pic?id=st52254022-677f-43e5-bb85-f457c716c494&user=search&operate=original?type=pic,http://store.is.autonavi.com/showpic/9926946396f2b73c676dcc93f07634f9?type=pic,http://store.is.autonavi.com/showpic/0fcf0bcc9827f4c28647f941472840fe?type=pic,http://store.is.autonavi.com/showpic/f0898b87e364aa4f984ec808ca7d4b9d?type=pic','120.121282,30.222719',2,0,'2026-04-09 08:36:29','2026-04-18 03:03:48'),(71,'浙江','灵隐寺','杭州市西湖区灵隐路法云弄1号','灵隐寺又称“云林寺”,坐落于西湖西面的灵隐山麓,这里环境清幽,是杭州最早的名刹,也是中国佛教禅宗十大古刹之一。历经一千七百年的风雨使灵隐寺成为历史与文化的宝库:天王殿上悬“云林禅寺”匾额,为清康熙帝所题;大雄宝殿前的石塔、天王殿前的石经幢均是五代十国吴越时的遗物;寺内珍藏的佛教文物有古代贝叶写经、东魏镏金佛像、明董其昌写本《金刚经》、清雍正木刻龙藏等珍贵宝物。灵隐寺还是“济公”道济和尚出家的寺庙,在道济禅师殿中供奉的一尊右手拿破扇、左手持念珠、右脚搁在酒缸上的佛像便是济公像。灵隐寺背靠北高峰、面朝飞来峰,尤其是著名的飞来峰虽然山不高,但山上有许多奇幻多变的洞壑,更遍布着五代以来的佛教石窟造像多达三百四十余尊,为我国江南少见的古代石窟艺术瑰宝。灵隐寺隐于山林,但香火常年旺盛,因为据说在这里祈福求愿极为灵验,特别是在初一、十五或者佛教盛日,善男信女从四面八方而来,更是人山人海。','75元','http://store.is.autonavi.com/showpic/813c10043bd5771688d757d996df7f87?type=pic,https://aos-comment.amap.com/B023B02842/headerImg/d1caf3485c8dcde24e889ace2ef4357e_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/d77383d34aeca5fda83776d3a97d82e0?type=pic','120.101406,30.240826',3,0,'2026-01-01 13:29:33','2026-02-11 10:16:23'),(72,'浙江','鲁迅故里','绍兴市越城区鲁迅中路241号','鲁迅故里是绍兴市内的一条历史街区,景区内不仅保留了不少当年的老建筑,还恢复了先生笔下的土谷祠、寿家台门等景观,百草园、三味书屋等儿时课本中的场景,也能在这里找到。景区的主道两边粉墙黛瓦,你可走进鲁迅故居参观先生诞生之地;还有屋后那曾是他儿时乐园的“百草园”;或是去“三味书屋”看一看少年鲁迅求学时用过的书桌;景区内还可参观鲁迅祖辈们的世居大宅、鲁迅笔下的“风情园”、陈列鲁迅生平事迹的纪念馆。','免费','http://store.is.autonavi.com/showpic/bb5b1680bbd53d85db6543a9ef258815?type=pic,http://store.is.autonavi.com/showpic/f039b438f1df6d1b5fa60efc09826daa?type=pic,http://store.is.autonavi.com/showpic/ea0d1941ec47b0581058d47f0e46da0e?type=pic,http://store.is.autonavi.com/showpic/9d7148554b0d5a676d026d8242d4d966?type=pic','120.584419,29.993263',5,0,'2026-03-27 10:53:14','2026-03-04 23:37:04'),(73,'浙江','普陀山','舟山市普陀山梅岑路85-1号','普陀山四面环海,风光旖旎,幽幻独特,被誉为“第一人间清净地”。山石林木、寺塔崖刻、梵音涛声,皆充满佛国神秘色彩。岛上树木丰茂,古樟遍野,鸟语花香,素有“海岛植物园”之称。全山共有66种百年以上的树木1221株。除千年古樟,还有被列为国家一级保护植物我国特有的珍稀濒危物种普陀鹅耳枥。岛四周金沙绵亘、白浪环绕,渔帆竞发,青峰翠峦、银涛金沙环绕着大批古刹精舍,构成了一幅幅绚丽多姿的画卷。岩壑奇秀,磐陀石、二龟听法石、心字石、梵音洞、潮音洞、朝阳洞等。大多名胜古迹,都与观音结下了不解之缘,流传着美妙动人的传说。它们各呈奇姿,引人入胜。普陀十二景,或险峻、或幽幻、或奇特,给人以无限遐想。','160元','http://store.is.autonavi.com/showpic/ce9be9624d9bdfd522d22708e184d26c?type=pic,http://store.is.autonavi.com/showpic/19e01764403658ced996b6c89cebb491?type=pic,http://store.is.autonavi.com/showpic/ae2c8eb77e7b518db7664c29547f3f97?type=pic,http://store.is.autonavi.com/showpic/739bb3698552ea409c85bd92cf3c0eee?type=pic','122.393559,30.000523',5,0,'2026-02-28 13:25:40','2026-04-14 20:17:09'),(74,'浙江','乌镇风景区','嘉兴桐乡市乌镇石佛南路18号','乌镇地处桐乡市北端,京杭大运河西侧,西临湖州市,北界江苏吴江县,为两省三市交界之处。作为首批中国历史文化名镇、中国十大魅力名镇、全国环境优美乡镇、国家5A级景区,乌镇素有“中国最后的枕水人家”之誉。','190元','http://store.is.autonavi.com/showpic/fc49ac95b5102ab0ba49277e830ce2f5?type=pic,http://store.is.autonavi.com/showpic/4bad0d4ef37ddb0abe587403e2d0bb62?type=pic,http://store.is.autonavi.com/showpic/9ea7d213f98d24e59ff11bf8fc38d80d?type=pic,http://store.is.autonavi.com/showpic/cb9b73ef61b02cc01b263642ccf66ebe?type=pic','120.486199,30.748876',4,0,'2026-04-14 13:08:44','2026-03-28 04:52:13'),(75,'浙江','南浔古镇','湖州市南浔区南浔镇人瑞路51号','南浔,建镇至今已有750多年历史,历史积淀浓郁,文化底蕴深厚,是国家AAAAA级旅游区。凭借独特的历史地位和人文景观,荣膺“中国十大魅力名镇”、“中国历史文化名镇”等称号。','免费','http://store.is.autonavi.com/showpic/5bd366082ae4a2839e247ad6654aa4e6?type=pic,http://store.is.autonavi.com/showpic/fc8c248add0f6a6500041295b5c142ce?type=pic,http://store.is.autonavi.com/showpic/240dedbe13a8b50e3132cec003d666e5?type=pic,http://store.is.autonavi.com/showpic/e083d7c7741bb633ce561681684aafb4?type=pic','120.43185,30.877924',4,0,'2026-01-01 08:54:55','2026-04-14 05:57:58'),(76,'浙江','莫干山','湖州市德清县莫干山风景名胜区','国家级风景名胜区莫干山位于德清县境内,因春秋末年,吴王派莫邪、干将在此铸成举世无双的雌雄双剑而得名,莫干山以竹、泉、云三胜景及“凉、绿、清、静”著称,有“清凉世界”的美誉,与北戴河、庐山、鸡公山并称为我国四大避暑胜地。莫干山总面积43平方公里,属天目山余脉,中心景区包括塔山、中华山、金家山、屋脊山、莫干岭、炮台山等,主峰塔山海拔719米。莫干山山峦起伏,植被覆盖率高达92%,风景秀丽多姿,它虽不及泰岱之雄伟、华山之险峻,却以绿荫如海的修竹、清澈不竭的山泉、星罗棋布的别墅、四季各异的迷人风光称秀于江南,有着“江南第一山”的美誉。莫干山景点众多,有风景秀丽的芦花荡公园、清幽雅静的武陵村、荡气回肠的剑池飞瀑、雄气逼人的怪石角、野味逼人的塔山公园,以及天池寺遗踪、莫干湖、旭光台、名家碑林、滴翠潭等30多处,隐于林间的173座近代别墅,荟萃了英、法、美、德、日、俄等国风格,有“别墅大观”的声名。','50元','http://store.is.autonavi.com/showpic/d8f6f57a833dd506f76cf52971205dbe?type=pic,http://store.is.autonavi.com/showpic/c7b0000b08328b399d3cda4f150a270c?type=pic,http://store.is.autonavi.com/showpic/0475950e03091715c0202e4bf8adb2c9?type=pic','119.83454,30.58436',3,0,'2026-02-05 03:05:06','2026-04-16 21:31:36'),(77,'浙江','雁荡山风景名胜区','温州市乐清市雁荡镇雁山路88号','雁荡三绝雁荡山在浙江省东南乐清县境内,是我国名山之一。雁荡山东西25公里,南北18公里,有景点三百多处。 雁荡山风景的特色,一是峰奇。雁荡的山峰多是拔地而起,但它们不同于玲珑多姿的桂林的山峰,而是高耸入云,气势磅礴。如展旗峰,远远看去,如一面大旗迎风招展。有人认为,就山峰的奇特、雄伟、多姿,雁荡不亚于黄山。二是瀑布秀丽,雁荡山有许多瀑布,有名称的达十八处。雁荡山的瀑布和贵州黄果树大瀑布的风格迥然而异,它不是以大取胜,而是以其优美的姿态打动游人。其最著名的瀑布是大龙湫、小龙湫和三折瀑。大龙湫高达190米终年奔泻不息。景色则随季节、风力、晴雨的变化而不同。 雁荡山是世界地质公园,总面积450万平方公里,有灵峰、灵岩、大龙湫、三折瀑、雁湖、显胜门、仙桥、羊角洞八大景区,素以峰、嶂、洞、瀑、门的奇秀造型而称胜,其中灵峰夜景、灵岩飞渡、龙湫飞瀑尤具神韵,被称为“雁荡三绝”。雁荡山形成于1.2亿年以前,是环太平洋大陆边缘火山带中最完整、最典型的白垩纪流纹质破火山,是流纹质火山岩的“天然博物馆”。对它的开山凿胜始于南北朝,兴于唐,盛于宋,其积淀了千年的宗教历史和山水文化。雁荡山集山水美学、地质科学、历史文化于一身,它属于中国,也属于世界;属于历史,也属于未来。','66元','http://store.is.autonavi.com/showpic/ffa44169cb7b950074ea8374c700eef5?type=pic,http://store.is.autonavi.com/showpic/9df3d4766e97e88475cc131f65ebb5fb?type=pic,http://store.is.autonavi.com/showpic/9a6713ae5c8cd02df5453077a96d8cc7?type=pic','121.033716,28.373656',4,0,'2026-03-06 02:22:42','2026-01-03 19:18:41'),(78,'四川','九寨沟诺日朗瀑布','阿坝藏族羌族自治州九寨沟县漳扎镇九寨沟内(北侧)','诺日朗瀑布,海拔2365米,位于诺日朗游客中心附近。瀑布宽270米,高24.5米,是中国大型钙化瀑布之一,也是中国最宽的瀑布,众多的影视剧曾在这里取景,包括中央电视台1986年版电视剧《西游记》的片尾就是在这里拍摄的。诺日朗瀑布在藏语里面的意思是雄伟壮观的瀑布。它呈多级下跌,宽达140米的水帘从两山间飞出,直泻百尺山崖,形成罕见的森林瀑布。瀑布对面建有一座观景台,站在台上,瀑布全景尽收眼底,秋季时,瀑布的三百米飞流在秋色、云雾的衬托下,化成了一幕波澜壮阔的画面。','免费','https://aos-comment.amap.com/B03450MOZE/headerImg/e7d8dd80b8dd90a3fd0f1ba15dc6fd4a_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/95f10f19605e0b1149deec4e1a577a10?type=pic,https://aos-comment.amap.com/B03450MOZE/headerImg/f3a2c8697aa7cafc5b179df91e74ca18_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/e00017b763bac85785affeeb92674189?type=pic','103.907291,33.163212',5,0,'2026-03-03 17:25:23','2026-03-02 05:10:52'),(79,'四川','佛国天堂','乐山市市中区篦子街乐山大佛景区内乐山大佛-碑林附近','峨眉山一直都是闻名中外的佛道教圣地，浓郁的佛教文化在这里传播蔓延，是我国著名的“佛国天堂”。峨眉山的美只有去过才知道，只有到过峨眉，到达金顶，看看翻腾的云海和日出，方知天地之美。','8元','http://store.is.autonavi.com/showpic/fba53d21ce8b8af45ee188724e2663ec?type=pic,http://store.is.autonavi.com/showpic/c4d0103477ae6f27c7d965305cd71029?type=pic,http://store.is.autonavi.com/showpic/ccaa3fae9f06f4935368c17ce183caf9?type=pic','116.45919,39.907444',4,0,'2026-04-26 21:38:12','2026-02-08 20:38:24'),(80,'四川','甘孜稻城亚丁景区','甘孜藏族自治州稻城县香格里拉镇','稻城亚丁,即亚丁自然保护区,也称亚丁景区,位于甘孜州稻城县南部,主要由“仙乃日、央迈勇、夏诺多吉”三座神山和周围的河流、湖泊和高山草甸组成,是中国保存最为完整的一处自然生态系统。因其独特的地貌和原生态的自然风光,而被誉为“蓝色星球上的最后一片净土”。 景区内不仅有壮丽神圣的雪山,还有辽阔的草甸、五彩斑斓的森林和碧蓝通透的海子,雪域高原最美的一切几乎都汇聚于此,这一切的一切都让人流连忘返。如当地虔诚的藏民一样,徒步转山是感受亚丁风光的最好方式。不过由于亚丁保护区海拔较高,全程徒步还是需要相当的体力。亚丁景区占地面积很大,加之海拔较高,游人一般采用“徒步+电瓶车+骑马”的方式游玩。常规路线为: 香格里拉镇售票中心(乘观光车)-扎灌崩-冲古寺草坪(乘电瓶车)-洛绒牛场(徒步)-牛奶海(徒步)-五色海(徒步)-洛绒牛场(乘电瓶车)-冲古寺(徒步)亚丁村(住宿)。全程约一整天时间。 其中:洛绒牛场-牛奶海-五色海-洛绒牛场段,也可乘坐景区运营的马帮,会省力很多。1. 亚丁景区面积大路程远,建议在亚丁村住宿一夜。亚丁村住宿多以民居、客栈为主,价格相对实惠,如非黄金周等旺季,无需提前预定。','免费','https://aos-comment.amap.com/B03440N0U0/headerImg/content_media_external_images_media_213755_1660366717981_370f4781.jpg?type=pic,http://store.is.autonavi.com/showpic/971a67951ad36e53ea0adccbf0773ccf?type=pic,https://aos-comment.amap.com/B03440N0U0/headerImg/437D35A1_4875_42BF_8D3B_7F738A2C81BC_L0_001_IMG_1868_1660218073215_199d5018.JPG?type=pic','100.286793,28.458898',3,0,'2026-03-28 14:17:24','2026-03-18 09:31:50'),(81,'四川','贡嘎雪山观景台','甘孜藏族自治州康定市新都桥镇官村71号','贡嘎山被称作“蜀山之王”不是没有道理的，这里你能看到簇拥的冰峰，宏伟的雪山，可是你却不会感到寒冷，在春秋两季，你甚至可以赤脚踏上冰川而不用担心“冰上不胜寒”。对于登山者而言，贡嘎山具有无与伦比的吸引力，其极限攀登声名远扬，每年吸引很多挑战者。登上峰顶，放眼望去，一片银白，你会有种胸怀天地，勇攀高峰成就感。这里的湖泊，冰峰千奇百怪，时有发生的冰崩更是让人震撼，这座神奇的山峰总是会给你意外的惊喜。日照金山更是美轮美奂，遇见都需要缘分。','免费','http://store.is.autonavi.com/showpic/6063646fb9db9df1712e86d50c1067a5?type=pic,http://store.is.autonavi.com/showpic/3f4531b01136a2aac9d98cd0cafa10ce?type=pic,http://store.is.autonavi.com/showpic/a9a538496dc0289d8c32789dfd4dd1a7?type=pic','101.531681,30.043404',4,0,'2026-01-03 04:46:59','2026-01-22 19:19:28'),(82,'四川','青城山景区','成都市都江堰市青城山路','青城山自古素有“青城天下幽”的美誉,分前山和后山两部分,前山是青城山的主体,道教文化、文物古迹多集中这里,这里也是一般游客口中的“青城山”;后山以自然风光取胜,是度假休闲的好去处。青城山前山以常观、上清宫为核心,宫观相望。建祖师殿、朝阳洞等人文景观与金鞭岩、石笋峰、丈人山等自然风光交相辉映。景区主要有老君阁、月城湖、天师洞、观音阁、上清宫、天然图画、祖师殿等景点。青城山后山与卧龙自然保护区相邻,里面随处可见潭水瀑布,绿草如茵。景区主要有金壁天仓、泰安古镇、水晶溶洞、三潭雾泉、龙隐峡栈道、双泉水帘、百丈长桥、白云群洞、天桥奇景等景点。游玩青城山一般来说半天足矣,无需住宿。山间随处有售卖饮食的店铺。如果时间充裕,可在此住宿一晚,便于第二天早起看日出,山间天师洞和上清宫皆有道观提供食宿。2019年9月1日起,通过团队实名制订票系统预订门票的游客,凭身份证直接刷证入园。','80元','https://aos-comment.amap.com/B001C06ESL/headerImg/ecddfbbcac1acf38c96ab0ea1a9116b2_2048_2048_80.jpg?type=pic,https://aos-comment.amap.com/B001C06ESL/headerImg/c8d31e73958ac2192b1c9a5be6b7c560_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/f3d5f65992c395f0990574572d057618?type=pic','103.563817,30.9044',5,0,'2026-04-13 10:16:21','2026-03-28 17:23:21'),(83,'四川','泸沽湖国家级风景名胜区草海','凉山彝族自治州盐源县泸沽湖草海五支洛村','草海因长年泥沙淤积,湖水较浅,生有茂密的芦苇而得名。15000亩草海,是镶嵌在泸沽湖东面的翡翠,几十种水生植物、奇珍异鸟和各种鱼、虾、贝、螺、蛙等构成罕见的生物大观园。草海内芦苇如墙,水路错综,红白衣裙的摩梭姑娘划着猪槽船出没其中,悠扬的“啊哈吧啦”民歌在水草丛中回荡。','免费','http://store.is.autonavi.com/showpic/91340ff21d32f0e851af23579243d3f7?type=pic,http://store.is.autonavi.com/showpic/f35f05167a45649fed3f521216e0983a?type=pic,http://store.is.autonavi.com/showpic/4bbe1d05b2f53bb9100b8fdb2e234db0?type=pic','117.038043,40.388453',4,0,'2026-01-07 08:07:43','2026-01-12 12:28:32'),(84,'四川','牛背山景区','雅安市荥经县牛背山镇','牛背山因山顶悬崖有巨石突出酷似牛头,山嵴细长貌似牛背而得名,被称为“中国最大观景台”。 牛背山的云海,浓密而均匀,壮阔而平缓,随处可见的瀑布云犹如阿凡达中“哈利路雅山”,让人感觉踏步于空中。 站在山顶不仅能观赏到蜀山之王的全貌,峨眉山、四姑娘山和二郎山等天府之国名山峻岭尽收眼底,运气好的话还能看到日照金山。 牛背山上的住宿还算方便,有很多藏族人搭建的大帐篷可以住宿,山上条件相对恶劣。 出发去牛背山前,一定要提前咨询客栈是否能开车上山,如果遇上山顶积雪路面结冰问题,车在“云海人家”就会停止,需徒步2-3小时上山。','免费','http://store.is.autonavi.com/showpic/03efde163a37894e72d1b52dda339ff2?type=pic,http://store.is.autonavi.com/showpic/36193b613a410cf4cabb31f397435247?type=pic,http://store.is.autonavi.com/showpic/16dc1444b4894b43cc6ef3e16d4cefe9?type=pic','102.416716,29.771273',3,0,'2026-02-08 13:59:34','2026-02-08 08:32:13'),(85,'广东','珠海长隆海洋王国','珠海市香洲区长隆大道','珠海长隆国际海洋度假区地处与澳门近在咫尺的中国国家级开放新区—横琴新区,是长隆集团投资建设的又一个世界级超大型综合主题旅游度假区。其应用国际先进技术和经验,自主创新,并采用最顶尖的科技设备、最顶级、最IN的设计和最完善的管理,全力打造一个集主题公园、豪华酒店、商务会展、旅游购物、体育休闲于一体的超级旅游度假区,这里将成为“世界级旅游巨无霸”和“世界的长隆”。 长隆海洋王国全面整合珍稀的海洋动物、顶级的游乐设备和新奇的大型演艺,全力打造世界顶级、规模最大、游乐设施最丰富也是最富有想象力的海洋动物为主题的休闲公园。长隆海洋王国拥有多项世界或行业之最:世界最大的海洋主题乐园;全球首创大型游乐设施与珍贵动物展区相结合的独特设计;亚洲第一台飞行过山车,其轨道全球最长;亚洲第一台水上过山车;世界最大的海洋馆和亚克力玻璃;世界最庞大的海洋主题花车巡游阵容等。','42元','http://store.is.autonavi.com/showpic/4181c6d55a338a4baef1fb715fb0e714?type=pic,http://store.is.autonavi.com/showpic/69fa49adb07d3b1e1d3641ede0c88ec4?type=pic,http://store.is.autonavi.com/showpic/3afc7f4bfa136e83a473823d8f8897e0?type=pic,http://store.is.autonavi.com/showpic/c3bbeadab458b66db6c8e7ccca9013b9?type=pic','113.538507,22.09875',5,0,'2026-03-18 00:42:25','2026-01-26 01:55:27'),(86,'广东','清远古龙峡','清远市清新区三坑滩村','清远古龙峡国际漂流赛场是国家AAAA级旅游景区,国际漂流大赛专业赛场,位于清远市清新区,距离广州市区仅68公里,广清高速直达景区。清远是中国漂流之乡,而古龙峡作为清远漂流的巅峰之作,以其全国最大的漂流落差、最刺激的漂流体验,被誉为:漂流之巅、落差之王。 古龙大峡谷景区内佳木葱茏、竹海清幽、湖瀑川连的自然景观展示着一种的远离尘嚣、超凡脱俗的静态之美。 古龙峡的万丈崖大瀑布,单体落差达101米,犹如巨龙从天而降,狂野无羁,气势磅礴。在悬崖壁峭壁撞击下,飞入峡谷激起惊涛骇浪。瀑布两层叠水的第一层如同一幅巨大的素绸, 折射着银色的闪光的和迷蒙的水雾。第二层似银河飞泻,串串银色珠帘飞溅而下, 彩虹幻出, 水声轰鸣。穿越500米的观光探险栈道, 就可以零距离体验扑面而来的震撼。','35元','http://store.is.autonavi.com/showpic/718d9b2e05fe3ce7110dfe5cddc8833d?type=pic,http://store.is.autonavi.com/showpic/adc585f227707f811f67bc97a7da18f0?type=pic,http://aos-cdn-image.amap.com/sns/ugccomment/61969d44-3427-4c96-b958-7cb21325d85f.jpg?type=pic','112.957388,23.78032',4,0,'2026-01-18 07:30:02','2026-01-12 07:43:50'),(87,'广东','广东大峡谷','韶关市乳源瑶族自治县大布镇','广东大峡谷位于乳源瑶族自治大布镇,距京珠高速公路乳源出口70千米。峡谷长达15千米,深300多米,属石英砂岩。原来大峡谷所在地只是山沟中的小盆地,由于受到燕山运动的影响,令地壳随地块抬升的扩张力,而使部分地块张裂下陷形成裂谷。 峡谷顶部地貌平缓,壶口瀑布从200多米的悬崖峭壁飞流直下,形成了气势磅礴的山水奇观。另有一条坡度达50度斜角的1386级石阶的“通天梯”可达谷底。峡谷沟壑纵横,奇峰林立,古木参天,构成一幅巧夺天工的山水画卷。 峡谷具有雄、奇、险、秀的独特景观。在这里除了能欣赏到大自然鬼斧神工的奇妙之作,使你游兴大增,同时也能对你的体能进行一次测验,是猎奇探险,别有洞天的生态旅游胜地。','40元','http://store.is.autonavi.com/showpic/d57bad437f2d454a0ca1412b5508d1db?type=pic,http://store.is.autonavi.com/showpic/5d97991b0901b7d8e0fb228b23592323?type=pic,http://store.is.autonavi.com/showpic/9a581be3ac3cfa6505e42acc20c50175?type=pic,https://aos-comment.amap.com/B0FFF5TSVJ/headerImg/5e422a34373f5c12043799596d42b7a5_2048_2048_80.jpg?type=pic','113.134548,24.508579',3,0,'2026-01-05 16:09:03','2026-04-20 09:33:46'),(88,'广东','南澳岛生态旅游区','汕头市南澳县粤东海面','南澳岛位于广东省和福建省交界的海域上,是广东省唯一的海岛县。 南澳岛的山水景致浑然天成,因为开发的比较少,人工修饰少,所以设施其实不太好,没有什么星级度假酒店,也没几家海鲜餐馆,晚上还没什么照明设备。但是也因此环境保护的不错,许多山石草木依然保留着最原始的面貌,海滩风景也显得不错。(但是由于南澳跨海大桥的建设,岛上的发展越来越快,之后不好说)除外岛上还有点历史遗迹,若只是来体验海滩风景,南澳岛还是很不错,没什么特别噪杂的环境,海滩也比较干净,吃吃海鲜,度个假。 岛上的主要景点有、、黄花山国家森林公园、南澳总兵府、宋井和叠石岩。','免费','http://store.is.autonavi.com/showpic/e9f039459c1748eb91260a567c8911e1?type=pic,http://store.is.autonavi.com/showpic/a812bf514d9beca987704c2322e5ae3d?type=pic,http://store.is.autonavi.com/showpic/558f9067ebc4af81101f317e307cd7c3?type=pic,http://store.is.autonavi.com/showpic/7976659ad692812fc4dc97965ca4a0d0?type=pic','117.0618,23.434553',5,0,'2026-02-22 23:21:43','2026-02-26 16:07:16'),(89,'广东','海陵岛风景区','阳江市江城区','海陵岛位于广东省的阳江市,享有“南方北戴河”和“东方夏威夷”之美称,被誉为一块未经雕琢的翡翠。海陵岛从2005年起到2007年连续3年被“中国国家地理”杂志社评为“中国十大最美海岛”之一。海陵岛四面环海,以水碧、沙净和游海水、住海边、食海鲜、买海味的特色驰名中外。海陵岛全年日照时间长,年平均气温22.8度,年晴天数310天,四季分明,气候宜人,是旅游度假的理想地方。海陵岛海鲜可谓物美价廉。交通:海陵岛交通网络四通八达,广州、深圳、珠海等地均有直达旅游车至阳江或闸坡,阳江车站直达快车不停往返于闸坡与阳江之间,旅游区内有中巴、电瓶车、黄包车穿梭往返、交通十分便利。','免费','http://store.is.autonavi.com/showpic/8d5a632168f18180c50b1a43df5a57f3?type=pic,http://store.is.autonavi.com/showpic/82599cb78a8e6e6c6818024030644f9f?type=pic,http://store.is.autonavi.com/showpic/9854de0732c8b329cc0306b56b60567c?type=pic,https://aos-comment.amap.com/B0FFK2MZ6X/headerImg/8aacb83416a1f9d1964287a72190c5fc_2048_2048_80.jpg?type=pic','111.911627,21.617774',4,0,'2026-01-05 10:31:14','2026-04-03 04:14:21'),(90,'广东','深圳东部华侨城','深圳市盐田区梅沙街道东海岸社区三洲田','深圳东部华侨城主要包括大侠谷生态乐园、茶溪谷度假公园、云海谷体育公园、大华兴寺、酒店群、天麓大宅等六大板块,体现了人与自然的和谐共处。 东部华侨城大侠谷生态乐园俯瞰深圳东部黄金海岸线,集山地郊野公园和都市主题公园于一体,体现生态动感旅游文化,实现了自然景观、生态理念与娱乐体验、科普教育的创新结合,主要包括:水公园、海菲德小镇、峡湾森林、生态峡谷、云海高地等五大主题区。 云顶观光区,海拔480米,是总览东部华侨城的至佳观景台,包括拥有亚洲唯一云上山顶极速转轮的云霄飞轮、110米高的自然之眼观光塔、全透明的玻璃延伸至悬崖之外的登峰造极、跨越山脉的云中走廊以及云海索道、丛林缆车等项目。','115元','http://store.is.autonavi.com/showpic/5d4d2adb3658766841b7cf80f3964920?type=pic,http://store.is.autonavi.com/showpic/a8e368c5b18a898f3643467daf813c65?type=pic,http://store.is.autonavi.com/showpic/71f7eb2430c9693b9089bcf1bef7e438?type=pic,http://store.is.autonavi.com/showpic/48652793482f951ca492547a4431b386?type=pic','114.287666,22.626673',4,0,'2026-03-29 13:38:04','2026-02-11 07:27:20'),(91,'广东','白水寨风景名胜区','广州市增城区北山路74号','白水寨风景名胜区位于增城市北部山区的派潭镇,现为省级风景名胜区,面积约170平方公里,北回归线穿越其中,被誉为北回归线上的瑰丽翡翠,属山岳型风景名胜区。白水寨山高林密,流水淙淙,树木葱郁。横跨三座高山,边接二大天池,号称“天南第一梯”。既有大型瀑布群,又有从悬崖峭壁上犹如狂龙从天而降的过钻瀑布。景区内崇山峻岭,群峰挺拔,海拔在1000米以上的山峰就有9座,其中最高峰为海拔1088米的牛牯嶂,山体高大、山势险峻、线条挺直,集雄、奇、险、秀于一身。白水寨风景名胜区拥有原始森林、浅滩湿地、峡谷天池等广东罕见自然生态资源,其中最令人瞩目的当属落差高达428.5米的全国内地落差最大瀑布——白水仙瀑。其形态优美,彷如仙女下凡,相传乃八仙之中何仙姑的化身。白水寨还是一个天然氧吧,山林飞瀑区域空气负离子含量高达11.25万个/立方厘米,位列广东景区之首。','60元','https://aos-comment.amap.com/B00140UFJS/headerImg/64e92f68fc65a155cbed88901387278c_2048_2048_80.jpg?type=pic,http://store.is.autonavi.com/showpic/bc951ad8c71f5f067a887991701eb635?type=pic,http://store.is.autonavi.com/showpic/220190ebcdf204615dc2bfaf1adfad2c?type=pic,http://store.is.autonavi.com/showpic/71387abcb7612b747461356763452e8a?type=pic','113.764201,23.583481',3,0,'2026-03-05 20:22:28','2026-03-17 07:30:22');

