DROP TABLE IF EXISTS `blog`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `blog` (
  `id` bigint unsigned DEFAULT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `title` varchar(255) DEFAULT NULL,
  `images` varchar(2048) DEFAULT NULL,
  `content` mediumtext,
  `location` varchar(255) DEFAULT NULL,
  `liked` int unsigned DEFAULT NULL,
  `tag` varchar(255) DEFAULT NULL,
  `type` varchar(20) DEFAULT NULL,
  `music_url` varchar(255) DEFAULT NULL,
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '游记状态',
  `deleted` int DEFAULT NULL,
  `route_id` bigint DEFAULT NULL COMMENT '关联路线ID',
  `itinerary_id` bigint DEFAULT NULL COMMENT '关联AI行程ID',
  `source` varchar(20) DEFAULT 'user' COMMENT '来源: user/ai'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

