  `food_factor` decimal(4,2) NOT NULL DEFAULT '1.00' COMMENT '餐饮费用系数',
  `ticket_factor` decimal(4,2) NOT NULL DEFAULT '1.00' COMMENT '景点费用系数',
  `misc_factor` decimal(4,2) NOT NULL DEFAULT '0.10' COMMENT '杂费系数（占总额比例）',
  `desc` varchar(100) DEFAULT NULL COMMENT '模板说明',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_theme` (`theme`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='预算主题模板表';
