  `user_id` varchar(64) NOT NULL COMMENT '用户ID',
  `session_title` varchar(255) DEFAULT '新对话' COMMENT '会话标题',
  `create_time` datetime NOT NULL COMMENT '会话创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '会话更新时间',
  `is_deleted` tinyint DEFAULT '0' COMMENT '是否删除（0未删除，1已删除）',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=150 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='聊天会话表';
