--
-- Table structure for table `checkout_order`
--

DROP TABLE IF EXISTS `checkout_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `checkout_order` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `order_no` varchar(64) NOT NULL COMMENT '订单编号',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `consignee_name` varchar(50) DEFAULT NULL COMMENT '收货人姓名',
  `consignee_phone` varchar(20) DEFAULT NULL COMMENT '收货人手机号',
  `consignee_address` varchar(300) DEFAULT NULL COMMENT '收货地址',
  `freight` double DEFAULT NULL COMMENT '运费',
  `total_price` decimal(10,2) NOT NULL COMMENT '订单总价',
  `remark` varchar(200) DEFAULT NULL COMMENT '买家备注',
  `pay_method` varchar(20) DEFAULT NULL COMMENT '支付方式: wechat/alipay/wallet',
  `coupon_id` bigint DEFAULT NULL COMMENT '使用的优惠券ID',
  `status` tinyint NOT NULL DEFAULT '0' COMMENT '订单状态: 0待发货 1运输中 2待收货 3完成',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_order_no` (`order_no`),
  KEY `idx_user_id` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=6 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='商城订单表';
/*!40101 SET character_set_client = @saved_cs_client */;

