INSERT INTO `delicacy` VALUES (1,'贵州','贵阳肠旺面','贵阳汤旺面是贵州极负盛名的一种风味小吃，在贵州众多的小吃中，肠旺面有山西刀削面的刀法，兰州拉面的劲道，四川担担面的滋润，武汉热干面的醇香，以色、香、味“三绝” 而著称，具有血嫩、面脆、辣香、汤鲜的风味和口感，以及红而不辣、油而不腻、脆而不生的特点。“肠旺”是“常旺”的谐音，寓意吉祥。','https://pic1.zhimg.com/80/v2-6e6dfa7e9386fa7fe140055527e7c884_1440w.webp','2024-05-08 16:30:25','2024-05-08 16:30:25'),(2,'北京','驴打滚','豆面糕又称驴打滚，北京吃中的古老品种之- -,它的原料是用黄米面加水蒸熟，和面时稍多加水和软些。另将黄豆炒熟后，轧成粉面。制作时将蒸熟发黄米面外面沾上黄豆粉面擀成片，然后抹上短沙馅(也可红糖)卷起来,切成100克左右的小块，撒上白糖就成了。制作时要求馅卷得均匀,层次分明，外表呈黄色，特点是香、甜、粘,有浓郁的黄豆粉香味儿。\n\n面糕以黄豆面为其主要原料，故称豆面糕。但为什么又称”驴打滚”呢?似乎是一种形象比喻，制得后放在黄豆面中滚一下， 如郊野真驴打滚,扬起灰尘似的，故而得名。这一点连前人也发出疑问。《燕都小食品杂咏》 中就说:“红糖水馅巧安排， 黄面成团豆里埋。何事群呼°驴打滚’，称名未免近诙谐。”还说:” 黄豆粘米，蒸熟，以红糖水馅，滚于炒豆面中，盘上售之，取名°驴打滚’真不可思议之称也。”可观”驴打滚”的叫法已约定俗成。如今,很多人只知雅号俗称，不知其名了。现各家小吃店一年四季都有供应,但大多数已不磺米面，改用江面了，外滚黄豆粉面，其颜色仍为黄色，是群众非常喜爱的一种小吃。','https://pic2.zhimg.com/80/v2-89e3641ed9f58c0a2be1365b10a6fff1_1440w.webp','2024-05-08 16:30:25','2024-05-08 16:30:25'),(3,'重庆','重庆火锅',NULL,'https://pic1.zhimg.com/80/v2-6f13456f3994b342c75fdbc1c2eedf84_1440w.webp','2024-05-08 16:30:25','2024-05-08 16:30:25'),(4,'四川','钵钵鸡',NULL,'https://pic3.zhimg.com/80/v2-64cdfa6d55b06df29709db62b07ba8ba_1440w.webp','2024-05-08 16:30:25','2024-05-08 16:30:25'),(5,'广东','广州肠粉',NULL,'https://pic4.zhimg.com/80/v2-dbe1f7766b463486b2b84384b05420df_1440w.webp','2024-05-08 16:30:25','2024-05-08 16:30:25'),(6,'浙江','西湖醋鱼',NULL,'https://pic3.zhimg.com/80/v2-2f548a69ad31882656ab8fbe5befe4a6_1440w.webp','2024-05-08 16:30:25','2024-05-08 16:30:25'),(7,'上海','生煎',NULL,'https://pic4.zhimg.com/80/v2-4f12978466b5cbd8b2f6d272c2023deb_1440w.webp','2024-05-08 16:30:26','2024-05-08 16:30:26'),(8,'山西','刀削面',NULL,'https://pic2.zhimg.com/80/v2-d27d0559288acfca37d7d431693a9fe5_1440w.webp','2024-05-08 16:30:26','2024-05-08 16:30:26'),(9,'江苏','盐水鸭',NULL,'https://pic3.zhimg.com/80/v2-2410a6b33c995e7cbe20d6cbd1b5cf7a_1440w.webp','2024-05-08 16:30:26','2024-05-08 16:30:26'),(10,'新疆','烤羊肉串',NULL,'https://pic2.zhimg.com/80/v2-344b4f59bb4e407dd66b08ba194805d5_1440w.webp','2024-05-08 16:30:26','2024-05-08 16:30:26'),(11,'福建','福州鱼丸',NULL,'http://inews.gtimg.com/newsapp_bt/0/7996595791/641','2024-05-08 16:30:26','2024-05-08 16:30:26'),(12,'广西','桂林米粉',NULL,'https://pic4.zhimg.com/80/v2-71e48d7b20ffd658b6482f157f9b8c2b_1440w.webp','2024-05-08 16:30:26','2024-05-08 16:30:26'),(13,'山东','德州扒鸡',NULL,'https://pic4.zhimg.com/80/v2-b040a26f0033a5fac7878f4d7b73d3bf_1440w.webp','2024-05-08 16:30:27','2024-05-08 16:30:27'),(14,'海南','椰子鸡',NULL,'https://ts4.cn.mm.bing.net/th?id=OIP-C.Z1w3fjWPi3TCsCkrR1OHpgHaJ9&w=215&h=289&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 16:30:27','2024-05-08 16:30:27'),(15,'台湾','台湾三杯鸡',NULL,'https://ts2.cn.mm.bing.net/th?id=OIP-C.XXmU0Z81mI4w5_zT0DHxswHaFj&w=288&h=216&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 16:30:27','2024-05-08 16:30:27'),(16,'湖南','酸辣椒炒猪大肠',NULL,'https://pic2.zhimg.com/80/v2-a08ef1938f4a62d082522e620b7939c1_1440w.webp','2024-05-08 16:30:27','2024-05-08 16:30:27'),(17,'西藏','酥油茶',NULL,'https://pic3.zhimg.com/80/v2-d0fa9f9027f2a06748875a59f605bd6a_1440w.webp','2024-05-08 16:30:27','2024-05-08 16:30:27'),(18,'陕西','洋芋擦擦',NULL,'https://pic3.zhimg.com/80/v2-c589e29807dc58fad042da6e2d5fba32_1440w.webp','2024-05-08 16:30:27','2024-05-08 16:30:27'),(19,'青海','牛羊肉',NULL,'https://pic1.zhimg.com/80/v2-f8575faf23ec977cfeb2a414bd594870_1440w.webp','2024-05-08 16:30:27','2024-05-08 16:30:27'),(20,'湖北','恩施土家酱香饼',NULL,'https://ts2.cn.mm.bing.net/th?id=OIP-C.JpP7lGfCeolXh2TucjY7hAHaE7&w=306&h=204&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 16:30:28','2024-05-08 16:30:28'),(21,'河北','正定八大碗',NULL,'https://ts1.cn.mm.bing.net/th?id=OIP-C.p84SVWsV6LZyqfuRcU0OXwHaGp&w=263&h=236&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 16:30:28','2024-05-08 16:30:28'),(22,'甘肃','兰州拉面',NULL,'https://ts1.cn.mm.bing.net/th?id=OIP-C.-SErL-IvVVpzKYsknLitVQHaEu&w=312&h=199&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 16:30:28','2024-05-08 16:30:28'),(23,'安徽','七都臭豆腐',NULL,'https://pica.zhimg.com/v2-28265984780550b93c43e2e24e0106cb_720w.jpg?source=d16d100b','2024-05-08 16:30:28','2024-05-08 16:30:28'),(24,'辽宁','马烧麦',NULL,'https://pic3.zhimg.com/80/v2-4d2fd162a52cd632b9a37214ac19a002_1440w.webp','2024-05-08 16:30:28','2024-05-08 16:30:28'),(25,'江西','三杯鸡',NULL,'https://pic3.zhimg.com/80/v2-1d7e72865456ef915c6afab53f68702a_1440w.webp','2024-05-08 16:30:28','2024-05-08 16:30:28'),(26,'河南','烩面',NULL,'https://pic2.zhimg.com/80/v2-10274a548bbe067d81631daed0c32cc5_1440w.webp','2024-05-08 16:30:29','2024-05-08 16:30:29'),(27,'天津','煎饼果子',NULL,'https://pic2.zhimg.com/80/v2-07fdbd730844061afbf47f9e09029551_1440w.webp','2024-05-08 16:30:29','2024-05-08 16:30:29'),(28,'吉林','铁锅靠大鹅',NULL,'https://pic1.zhimg.com/80/v2-dbd2397a6732fe36599639c8c4885c24_1440w.webp','2024-05-08 16:30:29','2024-05-08 16:30:29'),(29,'宁夏','手抓羊肉',NULL,'https://pic3.zhimg.com/80/v2-6fb8659e33f03a3134b16ada2e38c1c2_1440w.webp','2024-05-08 16:30:29','2024-05-08 16:30:29'),(30,'云南','傣族包烧',NULL,'https://pic3.zhimg.com/80/v2-142ef0c5dcfa4bafcbfe25bd828f7f72_1440w.webp','2024-05-08 16:30:29','2024-05-08 16:30:29'),(31,'黑龙江','大列巴',NULL,'https://pic1.zhimg.com/80/v2-01950caf43dc4d583a9b955114406fbc_1440w.webp','2024-05-08 16:30:29','2024-05-08 16:30:29'),(32,'内蒙古','内蒙烤全羊',NULL,'https://pic4.zhimg.com/80/v2-aeb7c816ce234ec52f53ebb36001985f_1440w.webp','2024-05-08 16:30:29','2024-05-08 16:30:29'),(51,'贵州','遵义羊肉粉','遵义羊肉粉是贵州省遵义市的一道特色小吃，用鲜羊肉熬汤，浇米粉，放羊肉片、调料而食，至今已有300余年制作历史，羊肉烂而不柴，口感美味，也是贵州著名的传统面食小吃。贵州各地均产羊肉粉，唯有遵义羊肉粉驰名，遵义羊肉粉的名气早在清代中叶就名扬遐迩，品尝过遵义羊肉粉的人，无不交口称赞。','https://pic2.zhimg.com/80/v2-59e8d1dc41300021fa3299aae4d77289_1440w.webp','2024-05-08 19:42:40','2024-05-08 19:42:41'),(52,'贵州','花溪牛肉粉','花溪牛肉粉发源地贵阳花溪地区，是贵州的一道特色名小吃，其独特的汤料，由多种名贵中草药精心严格制作，做出的牛肉粉与众不同，汤鲜味美，肉香。花溪牛肉粉选用上等黄牛，精制米粉，多髓牛骨，熬成鲜浓原汤，加上爽滑的蒸气米粉，配以醇香的牛肉，添上开胃的泡酸菜，点缀以新鲜芫荽，如果能吃辣，加上贵州特有的香炒辣椒面，一碗热气腾腾、色香味俱全的牛肉粉跃然呈现。','https://pic2.zhimg.com/80/v2-75bf6535ecc0b4a02971686704edc5d1_1440w.webp','2024-05-08 19:42:40','2024-05-08 19:42:40'),(53,'贵州','遵义豆花面','遵义豆花面是贵州省遵义市的一道特色小吃，该小吃是柔软滑爽，辣香味浓，风味特殊，其最初由佛教素面，创制于20世纪初，至今已有百多年历史，以面条为主要材料，烹饪的做法以煮菜为主，味道鲜香可口。遵义豆花面是遵义人独创，面条上盖着一团雪白的豆花，面条浸在豆浆之中。另加辣椒水一碟，辣椒水有讲究，有素、荤两种，素椒配有五种保密的佐料，荤椒还配有瘦肉丁、鸡肉丁、花生米、豆腐皮、金钩等，其味鲜美，将豆花与面挑入辣椒碟中吃。','https://pic4.zhimg.com/80/v2-13304ad213cf6b53b8b513145059dcc7_1440w.webp','2024-05-08 19:42:40','2024-05-08 19:42:40'),(54,'贵州','贵阳丝娃娃','贵阳丝娃娃，别名素春卷，是贵阳一种常见的地方传统小吃之一，也是贵阳最具贵州特色的风味小吃，在贵阳八大名小吃里排在了首位，充分反映出丝娃娃在贵阳人心目的地位。由于外形很像被子包着婴儿一般，就被称之为丝娃娃了。菜丝切得极细，红、白、黄、黑等各种色彩相间，十分漂亮。素菜脆嫩，酸辣爽口，开胃健脾。在贵州省会贵阳市众多丝娃娃小食摊多沿街而摆，颇具特色，有一二十个品种。','https://pic4.zhimg.com/80/v2-42bc8d398b13c18a05902b5b76d7ac63_1440w.webp','2024-05-08 19:42:40','2024-05-08 19:42:40'),(55,'贵州','都匀冲冲糕','都匀冲冲糕源于黔南布依族苗族自治州独山县，是用糯米制作成的一种食物，因其糕体是用蒸汽将食物冲蒸熟，并由圆竹筒底部顶压自然冲出，因此得以此名“冲冲糕”，至今已有百余年历史，现已传播到西南各个地区，成为贵州一道风味独特的传统美食小吃。冲冲糕以其质柔软香甜，色淡黄中偏红，地方味浓厚，口感有韧性的特点广受人们的喜爱。','https://pic2.zhimg.com/80/v2-18ee02dd2870911986b42b23479f6609_1440w.webp','2024-05-08 19:42:40','2024-05-08 19:42:40'),(56,'贵州','毕节汤圆','毕节汤圆是贵州西部毕节地区的一种著名小吃，汤圆用上等新糯米磨制成米浆，过滤晒干而成精制汤圆米粉，用冷水或开水调和米粉制成面皮，用苏麻、核桃、花生、蜜枣、芝麻、洗沙、玫瑰、桔饼、火腿、白糖、红糖、冰糖、香油等制成馅子。毕节汤圆的与众不同之处在于个小、皮薄、馅多、色鲜味美，一碗十个汤圆就有十种不同的味道，有的糯软爽滑，有的甜润甘美，有的肉质干香， 有的果味浓郁，成为享誉大江南北的贵州风味名吃。','https://pic4.zhimg.com/80/v2-756702cfe4e6afe95814e60f5b1961c7_1440w.webp','2024-05-08 19:42:40','2024-05-08 19:42:40'),(57,'贵州','贵阳米豆腐','贵阳米豆腐是贵州著名的少数民族小吃，也是贵州传统的夏令清凉小吃。此小吃润滑鲜嫩、酸辣可口。它是用大米淘洗浸泡后加水磨成米浆，然后加碱熬制，冷却，形成块状豆腐即成。食用时切成小片放入凉水中再捞出，盛入容器后，将切好的大头菜、盐菜、酥黄豆、酥花生、葱花等适合个人味口的不同佐料末与汤汁放于米豆腐上即可。','https://pic4.zhimg.com/80/v2-4f8e7d4936d848160cedd081cab9918f_1440w.webp','2024-05-08 19:42:40','2024-05-08 19:42:40'),(58,'贵州','水城羊肉粉','水城羊肉粉是贵州六盘水市的一道特色小吃，起源于上个世纪八十年代初，是以米粉和羊肉为主要原料，配以辣椒油、花椒粉、蒜苗、香葱、酸菜、香菜等佐料制作而成。一碗热气腾腾的羊肉粉做好后，吃起来羊肉鲜嫩、香气扑鼻，汤鲜味浓。水城羊肉粉吃法是，滚烫的羊肉汤，火辣辣的油辣椒，细腻的肉片，再配以白玉般的米线，一碗羊肉粉，直叫吃粉人一身大汗淋漓，意犹未尽。','https://pic3.zhimg.com/80/v2-c60b81abfb46095f01400f131bfafe4e_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(59,'贵州','贵阳豆腐圆子','贵阳豆腐圆子是贵阳的地方名小吃，是很有特色的贵州特色小吃，其中以雷家豆腐圆子最为出名。“赢得芳香四方溢，白玉入油亮似金。煮豆烯萁千年事，隔桌呼酒忆古今。金豆人磨转蟹黄，坡仙知味流涎长。俯见维雉牵衣儿，指说雷家圆子香。”这首诗对贵阳雷家豆腐圆子的赞誉可谓淋漓尽致。豆腐圆子最初由谁创制已难寻考，只知道其经雷家四代相传，工艺屡经改进，是深受食客喜爱的贵州地方风味小吃。','https://pic3.zhimg.com/80/v2-97d8fa169b61e181545bb45cb1bb88c2_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(60,'北京','艾窝窝','艾窝窝，北京传统风味小吃,年农历春节前后，北京的小吃店要上这个品种，- 直卖到夏末秋初，所以爱窝窝也属春秋品种，现在-四季都有供应。爱窝窝历史悠久，明万历年间内监刘若愚的《酌中志》中说:“以糯米夹芝麻为凉糕， 丸而馅之为窝窝，即之‘不落夹’他。”可观这种食品是用糯米洗净浸泡，尔后入笼屉蒸熟，晾凉后揉匀，揪成小剂，摁成圆皮，包上桃仁、芝麻仁、瓜子仁、青梅、金糕、白糖,拌和成馅，就成了明万历年间称之为窝的食品。为什么后来又成为爱窝窝呢?在清人李光庭的《乡谚解頤》一书中找到了说明。因为有一位皇帝爱吃这种窝窝,想吃或要吃时，就吩咐说:“ 御爱窝窝。”后来这种食品传入民间，一般百姓就不能也不敢说“御”字,所以省却了“御”字而称“爱窝窝”。此小吃在明代已流入民间，明代《金瓶梅》中记录当时流行的美味中就有爱窝窝。\n\n','https://pic4.zhimg.com/80/v2-eb3812176732993f27702f5add84719f_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(61,'北京','北京烤鸭','相传,北京烤鸭之美,是源于名贵品种的北京鸭，它是当今世界最优质的一种肉食鸭。以果\n\n木烤制，以色泽红艳，肉质细嫩,味道醇厚,肥而不腻的特色，被誉为\"天下美味”而驰名中\n\n外。除了能在北京品尝这么好的东西外,很多店铺更将烤鸭制成方便携带的北京特产。\n\n明初年间,佰姓爱吃南京板鸭，歸扡爱吃，据说明太祖朱元璋就“日食烤鸭-只”。逛\n\n里的御厨们就想方设法研制鸭馔的新吃法来讨好万岁爷,于是也就研制出了叉烧烤鸭和焖炉烤\n\n鸭这两种。叉烧烤鸭以“全聚德”为代表，而焖炉烤鸭则以\"便宜坊”最著名。金鲮烤鸭是选\n\n用肥大的草鸭为原料，净重要求在2. 5公斤左右。','https://pic2.zhimg.com/80/v2-7d9f38f61d788e8ae3ea71d3b840a681_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(62,'北京','炸酱面','炸酱面是北京富有特色的食物，棘码、炸酱拌面条而成。将黄瓜、香椿、芽靚亘\n切好或煮好，做成菜码备用。然后做炸酱,将肉J及葱姜等放在油里炒,再加入黄豆制作的黄\n酱或甜面酱炸炒,即成炸酱。面条煮熟后,捞出，烧上炸酱,拌以菜码,即成炸酱面。也有面\n条捞出后用凉水浸洗再加炸酱、菜码的,称“过水面”或者“凉面”。\n炸酱面在北京的流行程度,从老北京关于炸酱面的顺口溜可见-斑:“短嘴儿 香椿芽\n儿，炬菜切成段儿;菜末儿笋儿，狗牙蒜要掰两瓣儿;芽菜,去掉根儿，顶花带\n刺儿的黄瓜要切细丝儿;心美，切几批儿，焯江豆剁碎丁儿，小水萝卜带绿缨儿;辣椒麻油\n淋一乩，芥末泼到辣鼻眼儿。炸酱面虽只一小碗，七碟八碗是面码儿。\n在老北京,常见的是猪肉丁炸酱。似半肥瘦猪肉丁加葱、姜蒜等在油锅炸炒,加黄稀酱,\n盖上锅盖火咕嘟10分钟。当肉丁被黄酱咕嘟透了,肉皮红亮,香味四讲究的则是里脊丁炸\n酱三鲜(虾仁、脊、理)炸酱等,还有木樨(鸡蛋)炸酱、炸豆腐丁酱烧茄子丁酱\n等素品，而不腻。北人吃炸酱面,冷天讲究吃热的，之” 锅儿挑”(完全不过水) ,\n热天吃过水面，但汤要篦尽。根据季节佐以各种时鲜小菜，之“全面码孔” 。初春,掐\n头法的豆芽菜(称掐菜)、只有两片子叶的小水萝卜缨,并浇过年剩下的腊八醋。春深,\n在放上鲜花椒蕊儿,称花椒酱,面码儿则是青蒜、香椿芽掐菜、靛嘴、小水萝卜\n缨和丝(条)。初夏则以新蒜、焯过的鲜豌豆黄瓜丝、扁豆丝、韭锻等为面码儿。','https://pic3.zhimg.com/80/v2-734a35267c19931c55c0354fe5732c5a_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(63,'北京','奶油炸糕','北京小吃中奶油炸糕是富有营养的小吃品种。它用上好面粉为原料,先烧适开水,岍\n后,改用小火,将面粉倒人锅内，迅速搅拌直到面团由自变成灰白色，不粘手时,取出稍晾成\n面。白糖用水化开,草粉用水化开,遢鸡蛋液在碗内搅匀,分几次加入中,后一\n次加入奶油、糖水香草粉水，揉搓均。\n锅内倒花生油或生菜油，也可用牛油。但不宜豆油或芝麻油，因为后两种油容易抵消奶\n油味，伙烧至冒烟后,改用小火,此时将揉匀搅拌好的面团, 500克分成40个均匀小球，\n人油锅前手摁成圆饼，逐个下人油中,待饼膨起如球状，程金黄色时捞出，滚上白糖即\n成。奶油炸糕呈形，外里嫩,香味浓郁,营养,于消化。除奶油炸糕外,还有黄米\n面炸糕和江米面炸糕(用水磨米，质量最好) ,面均要加水和好后发酵，面和得不要太硬，要\n当揉进-点碱。制作时抓一块面约50 - 60克,脖指在中间按一个坑儿， 包进豆沙馅，将\n封严，随包随入温油炸至金黄色。此种炸糕外焦里嫩，香甜可口，很受欢迎。\n还有一种烫面炸糕，先把水烧开后，倒人面粉搅拌均均，面烫好后出锅分成大块,摊开晾\n凉,对上发面和适量碱面,揉匀揪成小剂，摁扁，包上红糖、桂花、面千拌匀制成的馅儿，\n用温油炸。此种炸糕外焦酥，里软嫩,易消化。\n','https://pic2.zhimg.com/80/v2-0db59fe50746abd129a4f01d76ad796d_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(64,'北京','糖耳朵','蜜麻花是北京小吃中常见名品','https://pic4.zhimg.com/80/v2-562d951841589e6b2f0f2035aed789cb_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(65,'北京','炒肝','今天给大家介绍一下北京炒肝','https://pic2.zhimg.com/80/v2-6f08d6d85236b04783ef5129b1962325_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(66,'北京','爆肚','爆肚是北京吃的名品，在清朝就流行于京城,很多达也嬉食爆肚。现在北名气\n\n的爆肚店还有很多，像天桥的爆肚石,陈安市场的爆肚王,们的爆肚张，其他的还有爆肚\n\n杨，爆肚冯等等都是,多家店铺的历史记逾百年,今兴盛不衰,骐缘由就是爆肚好吃。','https://pic1.zhimg.com/80/v2-32666388326c235b7ed6979493275dc4_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(67,'北京','豆汁儿','豆汁儿是北京独有的吃食儿，它是水磨绿豆制作粉丝或团粉时，把淀粉取出后,剩下来淡绿\n\n泛清色的汤汤水水，经过发酵而成的。','https://pic1.zhimg.com/80/v2-4f19d5455ddab77569df53bc1840dfb4_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(68,'北京','焦圈','北京小吃中的焦圈，妝老少都爱吃，酥脆油香的味儿，真叫人吃不够。','https://pic3.zhimg.com/80/v2-194df016bc3220cb453c3035c4d9125e_1440w.webp','2024-05-08 22:16:43','2024-05-08 22:16:43'),(69,'重庆','重庆小面',NULL,'https://pic4.zhimg.com/80/v2-a857f6908e545f6bb22aaf68a654db0f_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(70,'重庆','重庆酸辣粉',NULL,'https://pic2.zhimg.com/80/v2-03218d051993ac119cd829a165a0de41_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(71,'重庆','山城小汤圆',NULL,'https://pic4.zhimg.com/80/v2-4e3f8089699c25654f7b0e35ca31bc97_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(72,'重庆','重庆毛血旺',NULL,'https://pic3.zhimg.com/80/v2-ed62c307b7c29626f0fafb28d5b692e2_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(73,'重庆','重庆鸡杂',NULL,'https://pic3.zhimg.com/80/v2-2e5d05759cce38dbe0e497fa3cd44dae_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(74,'重庆','重庆烤鱼',NULL,'https://pic1.zhimg.com/80/v2-83de37933434616aa59c5916ebd11954_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(75,'重庆','辣子鸡',NULL,'https://pic3.zhimg.com/80/v2-e8e6642ee89ab889a3301166080f2ee2_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(76,'重庆','抄手',NULL,'https://pic3.zhimg.com/80/v2-75fd668ff71dc559be9e1db77e7d1eba_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(77,'重庆','豆花',NULL,'https://pic4.zhimg.com/80/v2-7b45f9ed421b430fc5f65303767f89cf_1440w.webp','2024-05-08 22:28:22','2024-05-08 22:28:22'),(78,'四川','担担面',NULL,'https://ts3.cn.mm.bing.net/th?id=OIP-C.x6pZMmQoErohyUhR5HLq7QHaE8&w=306&h=204&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 22:32:10','2024-05-08 22:32:10'),(79,'四川','肥肠粉',NULL,'https://pic1.zhimg.com/80/v2-12338b51e628885a7abf897085d18a3c_1440w.webp','2024-05-08 22:32:10','2024-05-08 22:32:10'),(80,'四川','夫妻肺片',NULL,'https://ts3.cn.mm.bing.net/th?id=OIP-C.ql6c5x-knDELx4HaP72RcwHaE8&w=306&h=204&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 22:32:10','2024-05-08 22:32:10'),(81,'四川','火鞭子牛肉',NULL,'https://pic2.zhimg.com/80/v2-bf638a5a4acd015681afad42aad6ba6d_1440w.webp','2024-05-08 22:32:10','2024-05-08 22:32:10'),(82,'四川','李庄白肉',NULL,'https://ts1.cn.mm.bing.net/th?id=OIP-C.oGrBrgVrUariAZMvSZP_IQHaEn&w=316&h=197&c=8&rs=1&qlt=90&o=6&dpr=1.5&pid=3.1&rm=2','2024-05-08 22:32:10','2024-05-08 22:32:10'),(83,'四川','罗江豆鸡',NULL,'https://pic2.zhimg.com/80/v2-3f6d863eb9c61f22b118f99c7a6a55f1_1440w.webp','2024-05-08 22:32:10','2024-05-08 22:32:10'),(84,'四川','奶汤面',NULL,'https://pic2.zhimg.com/80/v2-177a944622037ea9904eecab91b97109_1440w.webp','2024-05-08 22:32:10','2024-05-08 22:32:10'),(85,'四川','三大炮',NULL,'https://pic4.zhimg.com/80/v2-56d749a541a1d5e21b3f6c0cc5f1630f_1440w.webp','2024-05-08 22:32:10','2024-05-08 22:32:10'),(86,'广东','深圳光明乳鸽',NULL,'https://pic3.zhimg.c