DROP TABLE IF EXISTS `fare`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fare` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID（自增）',
  `departure_city` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '出发城市（如：北京市、上海市）',
  `arrival_city` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '到达城市（如：广州市、深圳市）',
  `train_number` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '车次编号（如：G123、D456、Z789）',
  `departure_time` datetime NOT NULL COMMENT '出发时间（精确到时分秒）',
  `arrival_time` datetime NOT NULL COMMENT '到达时间（精确到时分秒）',
  `price` decimal(10,2) NOT NULL COMMENT '票价（保留2位小数，单位：元）',
  `seat_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '座位类型（如：一等座、二等座、商务座、无座）',
  `remaining_seats` int NOT NULL DEFAULT '0' COMMENT '剩余座位数（默认0，无票时为0）',
  `fare_type` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '票价类型（如：成人票、儿童票、学生票、伤残军人票）',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '状态（0=有效，1=无效/下架，2=售罄）',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT '备注（如：临时加车、途经站点调整等）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间（自动填充当前时间）',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间（自动更新当前时间）',
  PRIMARY KEY (`id`),
  KEY `idx_departure_arrival` (`departure_city`,`arrival_city`),
  KEY `idx_departure_time` (`departure_time`),
  KEY `idx_train_number` (`train_number`)
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='票务信息表';
/*!40101 SET character_set_client = @saved_cs_client */;

