DROP TABLE IF EXISTS `fare_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `fare_order` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '订单ID（自增主键，从1开始）',
  `user_id` bigint NOT NULL COMMENT '用户ID（关联用户表）',
  `fare_id` bigint NOT NULL COMMENT '车票ID（关联车票表fare）',
  `departure_city` varchar(50) NOT NULL COMMENT '出发城市',
  `arrival_city` varchar(50) NOT NULL COMMENT '到达城市',
  `train_number` varchar(20) NOT NULL COMMENT '车次编号',
  `departure_time` datetime NOT NULL COMMENT '出发时间',
  `arrival_time` datetime NOT NULL COMMENT '到达时间',
  `price` decimal(10,2) NOT NULL COMMENT '订单总价（保留2位小数）',
  `seat_type` varchar(30) NOT NULL COMMENT '座位类型（如：一等座、二等座）',
  `remaining_seats` int NOT NULL COMMENT '剩余座位数',
  `fare_type` varchar(30) NOT NULL COMMENT '票价类型（如：成人票、学生票）',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '订单状态（0=未支付，1=已支付，2=已取消）',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '订单创建时间（自动填充）',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '订单更新时间（自动更新）',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`) COMMENT '用户ID索引（优化根据用户查订单）',
  KEY `idx_fare_id` (`fare_id`) COMMENT '车票ID索引（关联车票表）',
  KEY `idx_status` (`status`) COMMENT '订单状态索引（优化筛选订单）'
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='车票订单表';
