--
-- Table structure for table `itinerary_collab_message`
--

DROP TABLE IF EXISTS `itinerary_collab_message`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `itinerary_collab_message` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `room_id` bigint NOT NULL COMMENT '协作房间ID',
  `user_id` bigint NOT NULL DEFAULT '0' COMMENT '发言用户ID（0=AI/系统）',
  `role` varchar(10) NOT NULL DEFAULT 'user' COMMENT '消息角色：user/ai/system',
  `content` text NOT NULL COMMENT '消息内容',
  `msg_type` varchar(20) NOT NULL DEFAULT 'text' COMMENT '消息类型：text/ai-plan/system',
  `nickname` varchar(50) DEFAULT NULL COMMENT '发言用户昵称快照',
  `avatar` varchar(500) DEFAULT NULL COMMENT '发言用户头像快照',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_room_time` (`room_id`,`create_time`)
) ENGINE=InnoDB AUTO_INCREMENT=85 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='行程协作房间消息记录';
/*!40101 SET character_set_client = @saved_cs_client */;

