--
-- Table structure for table `itinerary_collab_room`
--

DROP TABLE IF EXISTS `itinerary_collab_room`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `itinerary_collab_room` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键（房间ID）',
  `invite_code` varchar(10) NOT NULL COMMENT '6位邀请码，大写字母+数字',
  `itinerary_id` bigint DEFAULT NULL COMMENT '关联的行程ID（AI生成后填入）',
  `creator_id` bigint NOT NULL COMMENT '创建者用户ID',
  `title` varchar(100) DEFAULT NULL COMMENT '协作主题，如"五一成都之旅"',
  `destination` varchar(100) DEFAULT NULL COMMENT '目的地',
  `days` tinyint NOT NULL DEFAULT '3' COMMENT '行程天数',
  `max_members` tinyint NOT NULL DEFAULT '10' COMMENT '最大成员数',
  `status` tinyint NOT NULL DEFAULT '1' COMMENT '状态：1规划中 2已生成行程 3已结束',
  `ai_summary` text COMMENT 'AI综合所有成员偏好的摘要',
  `expire_at` datetime NOT NULL COMMENT '邀请码过期时间，默认24小时',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_invite_code` (`invite_code`),
  KEY `idx_creator` (`creator_id`)
) ENGINE=InnoDB AUTO_INCREMENT=85 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='行程协作房间表';
/*!40101 SET character_set_client = @saved_cs_client */;

