--
-- Table structure for table `local_guide_cert`
--

DROP TABLE IF EXISTS `local_guide_cert`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `local_guide_cert` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `city` varchar(50) NOT NULL COMMENT '认证擅长城市',
  `intro` varchar(200) DEFAULT NULL COMMENT '向导简介',
  `cert_level` tinyint NOT NULL DEFAULT '1' COMMENT '1=本地达人 2=资深向导 3=官方推荐',
  `status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '0=审核中 1=已认证 2=已撤销',
  `apply_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `cert_time` datetime DEFAULT NULL COMMENT '审核通过时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_user_city` (`user_id`,`city`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='本地向导认证表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `local_guide_cert`
