--
-- Table structure for table `local_spot`
--

DROP TABLE IF EXISTS `local_spot`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `local_spot` (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `name` varchar(100) NOT NULL COMMENT '地点名称',
  `city` varchar(50) NOT NULL COMMENT '所在城市',
  `province` varchar(50) DEFAULT NULL COMMENT '所在省份',
  `address` varchar(200) DEFAULT NULL COMMENT '详细地址',
  `description` text COMMENT '地点描述（达人原话摘录或编辑整理）',
  `tips` varchar(500) DEFAULT NULL COMMENT '实用tips',
  `best_season` varchar(50) DEFAULT NULL COMMENT '最佳游览季节',
  `image_url` varchar(500) DEFAULT NULL COMMENT '代表图片URL',
  `source_blog_id` bigint DEFAULT NULL COMMENT '来源博客ID',
  `source_user_id` bigint DEFAULT NULL COMMENT '推荐达人用户ID',
  `category` varchar(50) DEFAULT NULL COMMENT '类别：natural/culture/food/art/market/other',
  `quality_score` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '综合质量分(0-100)',
  `view_count` int NOT NULL DEFAULT '0' COMMENT '被引用次数',
  `is_active` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否上架',
  `is_featured` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否精选',
  `is_verified` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否人工审核',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `idx_city` (`city`),
  KEY `idx_province` (`province`),
  KEY `idx_category` (`category`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='本地小众地点知识库';
/*!40101 SET character_set_client = @saved_cs_client */;

