INSERT INTO `local_spot` VALUES (1,'老成都茶馆','成都','四川省','成都市青羊区窄巷子32号深处','隐藏在宽窄巷子尽头的百年老茶馆，装修保留了80年代成都风貌，常有老成都人在此下棋打牌，是真正的本地生活场景，游客极少踏足。','不点茶水也可入内拍照，老板人很好；下午2-4点最安静；消费仅需一杯盖碗茶15元','全年','https://pic.imgdb.cn/item/6407b98df144a01007c1b9d3.jpg',NULL,NULL,'culture',92.50,156,1,1,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(2,'文殊坊后街夜市','成都','四川省','成都市青羊区文殊院街道文殊坊后侧小路','鲜有攻略提及的本地夜市，藏在文殊坊景区后侧，以烧烤、钵钵鸡、冷淡杯为主，价格是景区的一半，本地上班族下班后常来。','周四到周日晚上人最多，务必尝试\"麻辣豆花\"和\"军屯锅盔\"；停车很难，建议地铁2号线文殊院站步行5分钟','夏秋','',NULL,NULL,'food',88.00,89,1,1,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(3,'桂溪生态公园西区','成都','四川省','成都市高新区锦城大道旁桂溪生态公园西入口','成都本地人的后花园，与网红锦城公园相邻但人流量仅为其1/10。西区有大片野花草坪和小鸟乐园，适合带狗遛弯和拍照。','从锦城绿道骑行过来最佳；春天油菜花盛开最美；周末上午人稍多，建议周五傍晚前往','春夏','',NULL,NULL,'natural',79.50,67,1,0,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(4,'杭州小河直街老街区','杭州','浙江省','杭州市拱墅区小河路小河直街','运河边上保存最完整的老杭州民居街区，沿街老建筑几乎没有商业化改造，老居民仍在此居住晾晒，绝无游客喧嚣，是真正的烟火杭州。','早上7-9点是拍摄老街生活的最佳时间；附近有\"忆江南河坊街\"可解决午餐；不要闯进普通民居','全年','',NULL,NULL,'culture',90.00,203,1,1,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(5,'九溪烟树茶园小道','杭州','浙江省','杭州市西湖区龙坞茶镇九溪路尽头步行小道','九溪景区尽头沿小溪而上的茶农小道，无需门票，春茶季茶香四溢，溪边清澈见底，比龙井村游客少80%。','需步行约40分钟全程；4月明前茶时期最美；自备水；最后一段无路灯，天黑前返回','春季','',NULL,NULL,'natural',85.00,134,1,1,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(6,'西安老钢厂设计创意产业园','西安','陕西省','西安市雁塔区工业南路99号','废弃的工业厂区改造成文创园，保留了大量苏联援建时期的厂房建筑，是西安最有工业感的拍摄圣地，摄影爱好者和设计师的秘密据点。','工作日人极少，适合安静拍摄；园内有独立设计师小店和特色咖啡；周末偶有市集','全年','',NULL,NULL,'art',83.50,98,1,0,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(7,'大唐不夜城旁的回坊夜市深处','西安','陕西省','西安市莲湖区西羊市街、北广济街交叉一带','穿过大名鼎鼎的回民街，继续深入西羊市后的小巷，才是真正本地穆斯林居民的清晨菜市和傍晚夜市，烤肉和腊牛肉价格是前街的6折。','需要大胆深入小巷；早上8-10点买早餐最地道；对宗教习俗要尊重；建议结伴前往','全年','',NULL,NULL,'food',87.00,145,1,1,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(8,'厦门鼓浪屿内厝澳码头老社区','厦门','福建省','鼓浪屿岛内厝澳码头周边巷弄','与游客蜂拥的龙头路商业街相反，内厝澳码头周边是岛上原住民聚集地，老别墅、榕树下打牌的老人、晾晒的衣物，才是真实的鼓浪屿日常。','从内厝澳码头下船即到，可省去排队拥挤；午饭在此解决价格更实惠；适合下午3点后到访','全年','',NULL,NULL,'culture',89.00,176,1,1,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(9,'北京史家胡同博物馆','北京','北京市','北京市东城区史家胡同24号','藏在胡同里的微型博物馆，记录史家胡同百年变迁，免费参观，馆内展出老北京居民的生活物件，是了解真实胡同生活的最佳窗口。','免费参观，需提前在公众号预约；周一闭馆；下午3点光线最好；附近有老舍茶馆可消遣','全年','',NULL,NULL,'culture',91.00,221,1,1,1,'2026-05-25 11:39:57','2026-05-25 11:39:57'),(10,'北京三里屯工体北路背后的簋街尾段','北京','北京市','北京市东城区东直门内大街簋街最东端至外馆斜街一段','著名簋街的最东端靠近外馆斜街处，聚集了北京本地餐饮老板私下最喜欢的小馆子，比簋街中段价格低30%，不限时堂食，凌晨依然营业。','越靠近外馆斜街越本地化；推荐\"老刘麻辣小龙虾\"和\"四川人的饭馆\"；停车在北侧胡同','全年','',NULL,NULL,'food',86.00,108,1,0,1,'2026-05-25 11:39:57','2026-05-25 11:39:57');

