','8','2026-04-11 17:42:37','{\"text\": \"在没，哥子[可爱]\"}'),(48,'664da010140511ef8de1893d02d188b1','text','1',NULL,'2026-04-02 03:02:33','{\"text\": \"哈哈，冒个泡\"}'),(49,'7ee73b90140511ef85232fb8d20ca78f','text','3',NULL,'2026-02-03 18:04:55','{\"text\": \"+1[坏笑]\"}'),(50,'2b28a01014ba11efb83fff71410aae70','text','1','6','2026-01-16 17:16:55','{\"text\": \"铁铁\"}'),(51,'bae5d06014c911efa788cb56120190f0','text','3','18','2026-04-08 16:09:54','{\"text\": \"哈哈\"}'),(52,'e861a700183211ef93af0b9f8105aca0','text','21','16','2026-03-23 12:58:46','{\"text\": \"[勾引]\"}'),(53,'2977533354049937','text','6',NULL,'2026-04-26 00:24:08','{\"text\": \"[傲慢][傲慢][傲慢][傲慢]\"}'),(54,'2977533418013074','text','6',NULL,'2026-04-01 19:04:22','{\"text\": \"好\"}'),(55,'2984096965859730','text','1','3','2026-04-20 06:09:29','{\"text\": \"[OK]\"}'),(56,'2996921031461266','text','6','1','2026-02-04 05:34:17','{\"text\": \"我上早八\"}'),(57,'3042188089885074','text','1','44','2026-03-25 17:23:01','{\"text\": \"你好啊[偷笑]\"}'),(58,'3042188476817809','image','1','44','2026-03-18 06:12:15','{\"url\": \"https://wangzhenghai-oss.oss-accelerate.aliyuncs.com/goeasy-im-旅行/3042188468421009_uni-image.jpg\", \"name\": \"uni-image.jpg\", \"size\": 138025, \"width\": 1235, \"height\": 685, \"thumbnail\": \"https://wangzhenghai-oss.oss-accelerate.aliyuncs.com/goeasy-im-旅行/3042188468421009_uni-image.jpg?x-oss-process=image/resize,m_lfit,h_200\", \"contentType\": \"image/jpg\"}'),(59,'3042189405852049','text','1','44','2026-01-11 10:52:14','{\"text\": \"[NO]\"}');

