  `destination` varchar(255) NOT NULL COMMENT '目的地',
  `days` int NOT NULL COMMENT '天数',
  `nights` int NOT NULL COMMENT '晚数',
  `image` varchar(255) DEFAULT NULL COMMENT '路线图片',
  `price` decimal(10,2) NOT NULL COMMENT '价格',
  `type` varchar(50) NOT NULL COMMENT '路线类型（热门推荐、亲子游、自驾游等）',
  `travel_type` varchar(50) DEFAULT NULL COMMENT '旅行方式（跟团游、自由行等）',
  `highlights` text COMMENT '路线亮点（JSON格式）',
  `itinerary` text COMMENT '行程安排（JSON格式）',
  `cost` text COMMENT '费用说明（JSON格式）',
  `notice` text COMMENT '预订须知（JSON格式）',
  `features` text COMMENT '路线特色标签（JSON格式）',
  `status` tinyint DEFAULT '0' COMMENT '状态（0=有效，1=无效）',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `source` varchar(20) DEFAULT 'local' COMMENT '数据来源: local/ai/external',
  `created_by` varchar(20) DEFAULT 'system' COMMENT '创建来源: system/ai/user',
  `tags` text COMMENT '标签JSON',
  `route_detail` longtext COMMENT '完整路线结构JSON',
  `related_food_ids` text COMMENT '关联美食ID数组JSON',
  `related_hotel_ids` text COMMENT '关联酒店ID数组JSON',
  `related_poi_ids` text COMMENT '关联景点ID数组JSON',
  `ai_session_id` bigint DEFAULT NULL COMMENT 'AI会话ID',
  `request_key` varchar(128) DEFAULT NULL COMMENT '生成请求唯一键',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='旅游路线表';
