INSERT INTO `route` VALUES (1,'云南大理丽江5日游','云南 · 大理/丽江',5,4,'https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/5d61615a-4a36-4c5b-ace6-d3ffde8e1ba4.png',1999.00,'热门推荐','跟团游','[\"游览大理古城，感受白族文化\", \"骑行洱海，欣赏湖光山色\", \"登顶玉龙雪山，体验冰川魅力\", \"漫步束河古镇，享受宁静时光\", \"品尝云南特色美食\"]','[{\"dayTitle\": \"抵达大理\", \"activities\": [{\"time\": \"上午\", \"title\": \"抵达大理机场/火车站\", \"description\": \"专车接机/接站，前往酒店办理入住\"}, {\"time\": \"下午\", \"title\": \"大理古城自由活动\", \"description\": \"游览人民路、五华楼、洋人街，品尝大理特色美食\"}, {\"time\": \"晚上\", \"title\": \"入住酒店\", \"description\": \"入住大理古城内特色客栈\"}]}, {\"dayTitle\": \"大理洱海一日游\", \"activities\": [{\"time\": \"上午\", \"title\": \"洱海骑行\", \"description\": \"从才村码头出发，沿洱海西岸骑行，途经花语牧场、双廊\"}, {\"time\": \"中午\", \"title\": \"双廊午餐\", \"description\": \"品尝洱海特色鱼虾宴\"}, {\"time\": \"下午\", \"title\": \"南诏风情岛\", \"description\": \"乘船游览南诏风情岛，欣赏岛上风光\"}, {\"time\": \"晚上\", \"title\": \"洱海日落\", \"description\": \"在才村码头观赏洱海日落美景\"}]}]','{\"includes\": [\"4晚住宿（大理2晚，丽江2晚）\", \"行程中所列餐食\", \"景区门票（玉龙雪山门票、冰川大索道、印象丽江演出票等）\", \"当地交通费用\", \"导游服务费\"], \"excludes\": [\"往返大交通费用（机票/火车票）\", \"个人消费\", \"行程中未提及的其他费用\", \"旅游意外险\"]}','[\"请提前3天预订，以便安排行程\", \"玉龙雪山海拔较高，请做好高原反应的预防措施\", \"云南紫外线较强，请携带防晒霜、墨镜等防晒用品\", \"请尊重当地的民族风俗习惯\", \"如遇不可抗力因素导致行程变更，我们将尽力协调解决\"]','[\"古城游览\", \"洱海骑行\", \"玉龙雪山\", \"民族风情\"]',0,'2026-04-25 10:56:23','2026-04-04 00:12:16','local','system',NULL,NULL,NULL,NULL,NULL,NULL,NULL),(2,'四川成都九寨沟4日游','四川 · 成都/九寨沟',4,3,'https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/97da8810-5e2a-415e-bd1b-4b413ad4743f.gif',2599.00,'热门推荐','跟团游','[\"九寨沟\", \"黄龙\", \"成都美食\", \"熊猫基地\"]','[{\"dayTitle\": \"抵达成都\", \"activities\": [{\"time\": \"上午\", \"title\": \"抵达成都机场/火车站\", \"description\": \"专车接机/接站，前往酒店办理入住\"}, {\"time\": \"下午\", \"title\": \"成都市区自由活动\", \"description\": \"游览宽窄巷子、锦里古街，品尝成都美食\"}]}]','{\"includes\": [\"3晚住宿\", \"行程中所列餐食\", \"景区门票\", \"当地交通费用\", \"导游服务费\"], \"excludes\": [\"往返大交通费用\", \"个人消费\", \"行程中未提及的其他费用\"]}','[\"请提前3天预订\", \"九寨沟海拔较高，请做好高原反应的预防措施\"]','[\"九寨沟\", \"黄龙\", \"成都美食\", \"熊猫基地\"]',0,'2026-01-02 16:12:11','2026-03-31 08:24:07','local','system',NULL,NULL,NULL,NULL,NULL,NULL,NULL),(3,'海南三亚阳光海滩3日游','海南 · 三亚',3,2,'https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/1acc5991-4027-4d13-8fca-ca0f7d473a47.png',1799.00,'自驾游','自由行','[\"阳光海滩\", \"蜈支洲岛\", \"亚龙湾\", \"海鲜美食\"]','[{\"dayTitle\": \"抵达三亚\", \"activities\": [{\"time\": \"上午\", \"title\": \"抵达三亚机场/火车站\", \"description\": \"专车接机/接站，前往酒店办理入住\"}, {\"time\": \"下午\", \"title\": \"亚龙湾海滩\", \"description\": \"享受阳光海滩，自由活动\"}]}]','{\"includes\": [\"2晚住宿\", \"蜈支洲岛门票\", \"机场接送机\"], \"excludes\": [\"往返大交通费用\", \"个人消费\", \"餐饮费用\"]}','[\"请提前2天预订\", \"请携带防晒用品\"]','[\"阳光海滩\", \"蜈支洲岛\", \"亚龙湾\", \"海鲜美食\"]',0,'2026-03-23 17:24:02','2026-01-21 13:47:53','local','system',NULL,NULL,NULL,NULL,NULL,NULL,NULL),(4,'北京经典文化5日游','北京',5,4,'https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/5d61615a-4a36-4c5b-ace6-d3ffde8e1ba4.png',1599.00,'亲子游','跟团游','[\"故宫\", \"长城\", \"颐和园\", \"天坛\", \"胡同文化\", \"亲子互动\"]','[{\"dayTitle\": \"抵达北京\", \"activities\": [{\"time\": \"上午\", \"title\": \"抵达北京机场/火车站\", \"description\": \"专车接机/接站，前往酒店办理入住\"}, {\"time\": \"下午\", \"title\": \"故宫博物院\", \"description\": \"游览故宫，感受明清皇家文化\"}]}]','{\"includes\": [\"4晚住宿\", \"行程中所列餐食\", \"景区门票\", \"当地交通费用\", \"导游服务费\"], \"excludes\": [\"往返大交通费用\", \"个人消费\", \"行程中未提及的其他费用\"]}','[\"请提前3天预订\", \"故宫需提前预约门票\"]','[\"故宫\", \"长城\", \"颐和园\", \"天坛\", \"胡同文化\", \"亲子互动\"]',0,'2026-04-08 16:47:17','2026-03-08 18:32:47','local','system',NULL,NULL,NULL,NULL,NULL,NULL,NULL),(5,'张家界森林公园4日游','湖南 · 张家界',4,3,'https://wangzhenghai-oss.oss-cn-hangzhou.aliyuncs.com/97da8810-5e2a-415e-bd1b-4b413ad4743f.gif',1899.00,'徒步探险','跟团游','[\"天门山\", \"玻璃桥\", \"袁家界\", \"金鞭溪\"]','[{\"dayTitle\": \"抵达张家界\", \"activities\": [{\"time\": \"上午\", \"title\": \"抵达张家界机场/火车站\", \"description\": \"专车接机/接站，前往酒店办理入住\"}, {\"time\": \"下午\", \"title\": \"金鞭溪\", \"description\": \"徒步游览金鞭溪，欣赏自然风光\"}]}]','{\"includes\": [\"3晚住宿\", \"行程中所列餐食\", \"景区门票\", \"当地交通费用\", \"导游服务费\"], \"excludes\": [\"往返大交通费用\", \"个人消费\", \"行程中未提及的其他费用\"]}','[\"请提前3天预订\", \"建议穿舒适的运动鞋\"]','[\"天门山\", \"玻璃桥\", \"袁家界\", \"金鞭溪\"]',0,'2026-02-10 18:22:06','2026-01-04 12:12:10','local','system',NULL,NULL,NULL,NULL,NULL,NULL,NULL);

