--
-- Table structure for table `sys_region_area`
--

DROP TABLE IF EXISTS `sys_region_area`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `sys_region_area` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键',
  `sort` int DEFAULT '0' COMMENT '排序',
  `area_code` varchar(20) NOT NULL COMMENT '区级行政区划代码',
  `area_name` varchar(50) NOT NULL COMMENT '区级名称',
  `area_level` int NOT NULL COMMENT '区所属层级,1:省级，2:市级，3:区县级',
  `city_code` varchar(20) DEFAULT NULL COMMENT '市级行政区划代码',
  `city_name` varchar(50) DEFAULT NULL COMMENT '市级名称',
  `province_code` varchar(20) DEFAULT NULL COMMENT '省级行政区划代码',
  `province_name` varchar(50) DEFAULT NULL COMMENT '省级名称',
  `disabled` tinyint(1) DEFAULT '0' COMMENT '是否禁用',
  `parent_id` int DEFAULT '0' COMMENT '父级ID',
  `deleted` tinyint(1) DEFAULT '0' COMMENT '是否删除',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_area_code` (`area_code`),
  KEY `idx_area_level` (`area_level`),
  KEY `idx_province_code` (`province_code`),
  KEY `idx_city_code` (`city_code`),
  KEY `idx_parent_id` (`parent_id`)
) ENGINE=InnoDB AUTO_INCREMENT=659 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='区域表';
/*!40101 SET character_set_client = @saved_cs_client */;

